window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-08"] = {"date":"2026-04-08","featured":{"id":"featured-20260408","title":"WSJ Expõe Componentes Chineses nos Robôs Humanoides Americanos — Congresso Reage","summary":"O Wall Street Journal revelou que componentes-chave de muitos robôs humanoides fabricados nos EUA têm origem em fornecedores chineses, levantando preocupações de segurança nacional enquanto a tecnologia se aproxima da implantação comercial. O Congresso estaria preparando uma legislação baseada na proibição de drones DJI, que poderia restringir as cadeias de suprimento de empresas como Figure AI, Apptronik e outras. A revelação coloca toda a indústria americana de robótica humanoide em alerta: as empresas podem precisar relocalizar rapidamente ou diversificar o fornecimento de componentes antes que a pressão regulatória as force a isso.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=1200&h=600&fit=crop","source":"DroneXL / WSJ","url":"https://dronexl.co/2026/04/07/wsj-exposes-chinese-parts-inside-americas-humanoid-robots-congress-responds/","tags":["Política","Cadeia de Suprimentos","Humanoide","EUA–China"],"timestamp":"2026-04-07T12:29:00Z"},"articles":[{"id":"art-20260408-01","title":"Torobo: Tokyo Robotics Apresenta Humanoide Bípede que Rivaliza com o Atlas","summary":"A Tokyo Robotics estreou o Torobo, um humanoide bípede que gera comparações imediatas com o Atlas da Boston Dynamics tanto em forma quanto em qualidade de movimento. A empresa recentemente fez a transição do Torobo de uma plataforma com rodas para um design completamente bípede, um passo de engenharia significativo que sinaliza a crescente ambição do Japão na corrida dos robôs humanoides. O vídeo de demonstração que circula em r/robotics atraiu ampla atenção da comunidade global de robótica.","image":"https://external-preview.redd.it/NzVzaGlndWx4dHRnMYyLeldNXgLZBPv3d6qOutVa1HJXQyQ5d_cw4XkQ-nxZ.png?width=640&crop=smart&auto=webp&s=94d9ee42cddc77b76519588267d9f810a811be98","source":"Reddit r/robotics","url":"https://www.reddit.com/r/robotics/comments/1sf806y/torobo_humanoid_robot_by_tokyo_robotics/","tags":["Humanoide","Japão","Bípede"],"timestamp":"2026-04-07T20:39:12Z"},{"id":"art-20260408-02","title":"UBTECH e Honda Trading se Unem para Avançar Robôs Humanoides e Veículos Autônomos","summary":"A UBTECH Robotics assinou uma parceria estratégica com a Honda Trading para acelerar a comercialização de robôs humanoides e veículos logísticos autônomos. O acordo combina a plataforma Walker X da UBTECH com as extensas redes de distribuição e cadeia de suprimentos da Honda Trading na Ásia e além. Marca mais uma aliança significativa entre setores enquanto montadoras e fabricantes de robôs buscam compartilhar expertise em manufatura e escala.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"Pandaily","url":"https://pandaily.com/","tags":["UBTECH","Honda","Humanoide","Parceria"],"timestamp":"2026-04-08T02:38:00Z"},{"id":"art-20260408-03","title":"Para Onde a Robótica Está Indo: AI, Humanoides e o Surgimento da Inteligência Física","summary":"A abrangente análise setorial da Assembly Magazine traça a convergência de grandes modelos de linguagem e robótica física em uma nova disciplina chamada 'inteligência física'. O relatório argumenta que 2026 marca o ponto de inflexão onde os robôs transitam de máquinas de tarefa única para trabalhadores de propósito geral capazes de se adaptar a novos ambientes, baseando-se em insights de laboratórios líderes como Physical Intelligence (Pi) e Google DeepMind.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"Assembly Magazine","url":"https://www.assemblymag.com/","tags":["Inteligência Física","AI","Análise Setorial"],"timestamp":"2026-04-06T16:00:00Z"},{"id":"art-20260408-04","title":"Startup Chinesa de Robótica Busca Cientista-Chefe com Salário de US$ 18 Milhões para Desafiar Tesla Optimus","summary":"Uma startup chinesa de robótica humanoide que desenvolve um concorrente direto do Optimus da Tesla está oferecendo um salário anual de US$ 18 milhões para atrair um cientista-chefe de classe mundial, segundo o Business Insider. O extraordinário pacote de remuneração reflete a intensificação da concorrência por talentos de elite em AI-robótica enquanto empresas chinesas correm para fechar a lacuna com seus pares americanos. A empresa não identificada estaria respaldada por grandes investidores alinhados ao Estado.","image":"https://images.unsplash.com/photo-1593642632559-0c6d3fc62b89?w=400&h=250&fit=crop","source":"Business Insider","url":"https://www.businessinsider.com/","tags":["China","Tesla Optimus","Talentos","Financiamento"],"timestamp":"2026-04-06T10:20:00Z"},{"id":"art-20260408-05","title":"Avanço em Atuador Resiliente Pode Viabilizar Robôs Macios no Espaço","summary":"Pesquisadores desenvolveram uma nova classe de atuadores projetados para resistir às condições extremas do espaço — incluindo vácuo, radiação e variações de temperatura — sem falha mecânica. O sistema usa um composto elastomérico inovador que mantém o desempenho em uma faixa mais ampla que atuadores de robótica macia anteriores, abrindo caminhos para sistemas robóticos implantáveis em futuras missões lunares e marcianas. O trabalho foi publicado em uma revista científica de materiais revisada por pares.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/new-actuator-could-boo.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-resilient-actuator-potential-space-ready.html","tags":["Robótica Macia","Espaço","Atuador","Pesquisa"],"timestamp":"2026-04-05T14:00:00Z"},{"id":"art-20260408-06","title":"O que Amazon Viu na Estratégia Humanoide da Fauna Robotics","summary":"O The Robot Report obteve informações sobre a justificativa estratégica da Amazon para adquirir a Fauna Robotics, fabricante do humanoide Sprout. A Amazon foi atraída pelo foco único da Fauna em manipulação dextral em escala humana em ambientes não estruturados — uma lacuna de capacidade que os robôs de armazém existentes da Amazon não conseguem preencher. A aquisição sinaliza a intenção da Amazon de ir além da automação fixa e implantar humanoides como trabalhadores generalistas flexíveis em toda a sua rede de distribuição.","image":"https://images.unsplash.com/photo-1635070041078-e363dbe005cb?w=400&h=250&fit=crop","source":"The Robot Report","url":"https://www.therobotreport.com/what-amazon-saw-in-fauna-robotics-humanoid-strategy/","tags":["Amazon","Fauna Robotics","Humanoide","Aquisição"],"timestamp":"2026-04-07T15:08:00Z"},{"id":"art-20260408-07","title":"Sequenciamento Autônomo e Recuperação de Erros na Construção Robótica","summary":"O AZoBuild reporta nova pesquisa que demonstra o sequenciamento autônomo de tarefas e a recuperação de erros em tempo real para robôs de construção. O sistema pode replanejar em tempo real quando os componentes estão desalinhados ou as ferramentas falham, um passo importante em direção à operação verdadeiramente autônoma em canteiros de obras. Testes de campo mostraram o robô completando tarefas de alvenaria em múltiplas etapas com taxa de sucesso de 91% sem intervenção humana.","image":"https://images.unsplash.com/photo-1601584115197-04ecc0da31d7?w=400&h=250&fit=crop","source":"AZoBuild","url":"https://www.azobuild.com/","tags":["Construção","Autônomo","Pesquisa"],"timestamp":"2026-04-07T15:18:00Z"},{"id":"art-20260408-08","title":"Big-D Construction Expande Implantação de Robótica Autônoma com FieldAI","summary":"O gigante americano da construção Big-D Construction aprofundou sua parceria com a FieldAI, implantando robôs autônomos em múltiplas obras ativas. Os robôs realizam levantamentos de local, monitoramento de progresso e inspeções de segurança usando visão computacional alimentada por AI, reduzindo a necessidade de rondas manuais. A implantação é uma das maiores em robótica comercial no setor de construção dos EUA até o momento.","image":"https://roboticsandautomationnews.com/wp-content/uploads/2026/04/field-ai-bid-d-1.png","source":"Robotics & Automation News","url":"https://roboticsandautomationnews.com/2026/04/07/big-d-expands-construction-operations-with-fieldai-as-robotics-adoption-accelerates/100362/","tags":["Construção","FieldAI","Autônomo","Comercial"],"timestamp":"2026-04-07T07:42:00Z"},{"id":"art-20260408-09","title":"Robôs AI da Maximo Instalam Mais de 100 MW de Painéis Solares Usando Tecnologia NVIDIA","summary":"A Maximo, startup de robótica de construção alimentada por AI, cruzou a marca de 100 megawatts de instalações de painéis solares realizadas por seus robôs autônomos. Destacada durante a cobertura da Semana Nacional de Robótica da NVIDIA, os robôs da Maximo usam NVIDIA Isaac para percepção e planejamento, permitindo-lhes lidar com a variabilidade do local e as condições climáticas. O feito demonstra que a AI física já pode escalar de forma confiável a infraestrutura de energia renovável.","image":"https://blogs.nvidia.com/wp-content/uploads/2026/04/robotics-tech-blog-nrw-rolling-blog-1280x680-1.jpg","source":"NVIDIA / Reddit r/robotics","url":"https://blogs.nvidia.com/blog/national-robotics-week-2026/#maximo","tags":["NVIDIA","Energia Solar","Robô de Construção","AI"],"timestamp":"2026-04-07T09:55:13Z"},{"id":"art-20260408-10","title":"Pulseira de Ultrassom do MIT Dá aos Robôs Destreza em Nível Humano","summary":"Pesquisadores do MIT desenvolveram uma pulseira baseada em ultrassom que captura movimentos musculares sutis no antebraço humano com precisão de milissegundos, permitindo mapear esses movimentos diretamente em mãos robóticas. Nos testes, uma luva robótica controlada pela pulseira igualou pela primeira vez as pontuações de destreza humana em tarefas de manipulação padronizadas. O wearable não invasivo pode se tornar uma interface-chave para teleoperação e coleta de dados de treinamento robótico.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"MIT / Tech Xplore","url":"https://techxplore.com/","tags":["MIT","Destreza","Wearable","Pesquisa"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-11","title":"ForSight Robotics Realiza a Primeira Cirurgia de Catarata Totalmente Robótica do Mundo","summary":"A ForSight Robotics anunciou a primeira cirurgia de catarata totalmente autônoma realizada por robô do mundo usando sua plataforma JASPER. O procedimento foi concluído sob supervisão médica sem nenhuma intervenção manual durante a operação. O marco é considerado significativo porque a cirurgia de catarata requer precisão submilimétrica e é um dos procedimentos cirúrgicos de maior volume em todo o mundo, representando um enorme mercado potencial para a robótica médica.","image":"https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=400&h=250&fit=crop","source":"ForSight Robotics","url":"https://www.forsight-robotics.com/","tags":["Médico","Cirurgia","Autônomo","Marco"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-12","title":"Microsoft, NVIDIA e Universidade de Washington Revelam OmniReset para AI em Robótica","summary":"Uma equipe conjunta da Microsoft, NVIDIA e da Universidade de Washington lançou o OmniReset, um framework de código aberto que permite aos sistemas robóticos se recuperar automaticamente de falhas e se redefinir para estados seguros durante o treinamento e a implantação. O OmniReset aborda um dos principais gargalos na transferência de simulação para o mundo real — a necessidade de redefinições humanas quando os robôs ficam presos — e pode acelerar drasticamente o aprendizado por reforço em escala.","image":"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=400&h=250&fit=crop","source":"ETIH / EdTech Innovation Hub","url":"https://www.edtechinnovationhub.com/","tags":["Microsoft","NVIDIA","Código Aberto","Aprendizado por Reforço"],"timestamp":"2026-04-07T23:06:00Z"},{"id":"art-20260408-13","title":"Coreia do Sul Mira 2030 como Janela Crítica para Liderança no Mercado de Robôs Humanoides","summary":"Funcionários do governo sul-coreano e analistas do setor identificaram a janela 2026-2030 como decisiva para o país estabelecer uma posição de liderança no mercado de robôs humanoides. A estratégia da Coreia do Sul combina as capacidades de fabricação da Samsung, Hyundai e LG Group com investimento agressivo em P&D, visando desafiar a China e os EUA. O DongA Science informa que o governo está preparando um fundo de competitividade em robótica de vários bilhões de dólares.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"DongA Science","url":"https://www.dongascience.com/","tags":["Coreia do Sul","Política","Humanoide","Mercado"],"timestamp":"2026-04-08T01:38:00Z"},{"id":"art-20260408-14","title":"China Testa Robôs Humanoides para Tarefas de Controle de Fronteira com o Vietnã","summary":"A China começou a pilotar robôs humanoides em operações de patrulha e controle de fronteira ao longo de sua fronteira com o Vietnã, segundo o ECOticias. Os robôs estão equipados com câmeras térmicas, reconhecimento facial e locomoção adaptativa ao terreno, e estão sendo avaliados para monitoramento de postos de controle e vigilância de perímetro. A implantação está entre os primeiros usos conhecidos de robôs em forma humanoide para operações de segurança de fronteira nacional.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"ECOticias","url":"https://www.ecoticias.com/","tags":["China","Segurança de Fronteira","Humanoide","Defesa"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-15","title":"Maior Estaleiro dos EUA se Une à GrayMatter Robotics em AI Física","summary":"A Huntington Ingalls Industries, o maior estaleiro da Marinha dos EUA, fez parceria com a GrayMatter Robotics para implantar sistemas de AI física em tarefas complexas de soldagem e montagem em navios militares. Os robôs da GrayMatter usam visão 3D e AI adaptativa para lidar com as condições não estruturadas e variáveis da construção naval — um ambiente historicamente difícil de automatizar. O acordo evidencia o crescente interesse em robótica para a fabricação industrial de defesa.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"Manufacturing.net","url":"https://www.manufacturing.net/","tags":["Defesa","GrayMatter","Construção Naval","AI Física"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-16","title":"BASF e Sevnce Robotics se Unem para Automação Inteligente de Produção Química","summary":"O gigante químico BASF assinou uma parceria com a Sevnce Robotics para implantar robôs autônomos de inspeção e amostragem dentro de suas instalações de produção química. Os robôs conseguem operar em ambientes corrosivos e perigosos impróprios para trabalhadores humanos, realizando verificações de rotina e detecção de anomalias 24 horas por dia. O acordo faz parte da estratégia mais ampla de digitalização da BASF e destaca o uso crescente de robótica em setores industriais de alto risco.","image":"https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=400&h=250&fit=crop","source":"NovusLight","url":"https://www.novuslight.com/","tags":["BASF","Industrial","Robô de Inspeção","Química"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-17","title":"Robôs Humanoides Impulsionam Desenvolvimento de Sensores Táteis enquanto Empresas de Taiwan Competem","summary":"A cadeia de suprimentos de semicondutores e eletrônicos de Taiwan está pivotando para o desenvolvimento de sensores táteis, impulsionada pela demanda em forte crescimento dos fabricantes de robôs humanoides globalmente. O Digitimes informa que empresas como Merry Electronics e outras estão correndo para desenvolver sensores de pressão de alta densidade semelhantes à pele para mãos robóticas. A dominância de Taiwan na manufatura de precisão lhe confere uma vantagem estrutural para fornecer essa categoria emergente de componentes.","image":"https://img.digitimes.com/newsshow/20260407vl200_files/1_b.jpg","source":"Digitimes","url":"https://www.digitimes.com/news/a20260407VL200/humanoid-robot-tactile-sensor-taiwan.html","tags":["Taiwan","Sensores Táteis","Humanoide","Cadeia de Suprimentos"],"timestamp":"2026-04-08T00:04:00Z"},{"id":"art-20260408-18","title":"Nanorobôs Alimentados por Luz Capturam e Removem Bactérias da Água","summary":"Cientistas demonstraram nanorobôs alimentados por luz visível capazes de buscar e capturar bactérias nocivas em amostras de água com alta eficiência. Os robôs usam química fotocatalítica para se propulsar e destruir patógenos ao contato, sem necessitar de fonte de energia externa além da luz ambiente. O avanço tem aplicações potenciais na purificação de água, entrega direcionada de medicamentos e tratamento de infecções.","image":"https://www.azorobotics.com/images/news/ImageForNews_15432_17304078587295526.jpg","source":"AZoRobotics","url":"https://www.azorobotics.com/News.aspx?newsID=15432","tags":["Nanorobótica","Médico","Água","Pesquisa"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-19","title":"Serve Robotics Estreia Robô de Entrega com AI Conversacional no NVIDIA GTC","summary":"A Serve Robotics apresentou um robô de entrega de calçada de nova geração com AI conversacional no NVIDIA GTC 2026. O robô pode se comunicar com pedestres, responder em tempo real a perguntas sobre o status da entrega e lidar com interações complexas com pedestres usando processamento de AI na borda. A Serve, que opera entregas do Uber Eats em Los Angeles, afirma que a capacidade conversacional melhora a segurança e a experiência do cliente em ambientes urbanos densos.","image":"https://cdn.sanity.io/images/dh33lj7y/production/ba522acc2978502c9d69447015fb70bd295bc95b-1200x630.jpg","source":"Serve Robotics / NVIDIA","url":"https://www.serverobotics.com/blog","tags":["Serve Robotics","Entrega","AI Conversacional","NVIDIA"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-20","title":"POSCO Group Investe 7 Bilhões de Won na Empresa de Automação Robótica Brils","summary":"O conglomerado siderúrgico sul-coreano POSCO Group comprometeu 7 bilhões de wons coreanos (aproximadamente US$ 5 milhões) na Brils, uma startup de automação robótica especializada em aplicações industriais pesadas. O investimento financiará o desenvolvimento pela Brils de sistemas robóticos orientados por AI para operações em siderúrgicas, onde temperaturas extremas e requisitos de precisão há muito desafiam os esforços de automação. Isso sinaliza a adoção acelerada da robótica de próxima geração pela indústria pesada tradicional.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"BusinessKorea","url":"https://www.businesskorea.co.kr/","tags":["POSCO","Coreia do Sul","Financiamento","Industrial"],"timestamp":"2026-04-07T11:00:00Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-07"] = {"date":"2026-04-07","featured":{"id":"featured-20260407","title":"Amazon adquire a Fauna Robotics, criadora do robô humanoide Sprout","summary":"A Amazon adquiriu a Fauna Robotics, a startup por trás do robô humanoide Sprout, em um acordo que acelera dramaticamente o avanço do gigante do comércio eletrônico na direção da AI incorporada para automação de armazéns. A aquisição marca um dos maiores buyouts de robótica humanoide até o momento, sinalizando que as grandes empresas de tecnologia estão indo além de parcerias para a propriedade direta de empresas de robótica. O Sprout foi construído especificamente para tarefas flexíveis de pegar e colocar em centros de distribuição — áreas onde robôs industriais convencionais há muito tempo têm dificuldades. Com a escala logística da Amazon e sua infraestrutura de AI, o Sprout pode passar do piloto para a implantação em massa em sua vasta rede global de armazéns em questão de anos.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/amazon-buys-fauna-robo.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-amazon-buys-fauna-robotics-maker.html","tags":["Amazon","Humanoide","Aquisição","Armazém"],"timestamp":"2026-04-07T02:29:52Z"},"articles":[{"id":"art-20260407-01","title":"Mão robótica sem motor usa atuador de memória de forma para preensões em menos de um segundo","summary":"Pesquisadores demonstraram uma mão robótica que opera sem motores elétricos convencionais, dependendo em vez disso de um novo atuador bidirecional de liga com memória de forma capaz de se reconfigurar em menos de um segundo. O design simplifica drasticamente a complexidade mecânica — preensores robóticos tradicionais requerem dezenas de motores e cabos — enquanto mantém uma manipulação confiável. Ao explorar a atuação no nível do material, a mão adapta sua geometria de preensão dinamicamente em ambientes não estruturados. O avanço pode reduzir os custos tanto para sistemas de próteses quanto para preensores industriais.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/twoway-shape-memory-al.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["Atuador","Preensor","Robótica Mole","Manipulação"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-02","title":"Superando barreiras fundamentais de engenharia no desenvolvimento da robótica humanoide","summary":"Um novo white paper da IEEE Spectrum examina os persistentes obstáculos de hardware e software que impedem os robôs humanoides de passar do protótipo para a produção em escala. Os principais desafios incluem a densidade de energia das baterias, a lacuna entre benchmarks de destreza em laboratório e a confiabilidade no mundo real, e a ausência de ecossistemas de componentes padronizados. O documento argumenta que a colaboração entre empresas sobre padrões de atuadores e sensores poderia comprimir os prazos de desenvolvimento em anos — enquanto grandes players de Boston Dynamics a Figure AI correm para implantar humanoides comercialmente.","image":"https://assets.rbl.ms/65106483/origin.png","source":"IEEE Spectrum","url":"https://content.knowledgehub.wiley.com/engineering-challenges-and-component-strategies-in-humanoid-robotics-from-prototype-to-production/","tags":["Humanoide","Engenharia","Indústria","Roteiro"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-03","title":"Enxame de robôs sem eletrônica, baterias ou cérebros demonstra comportamento emergente","summary":"Cientistas criaram um enxame de robôs que opera inteiramente sem eletrônica, baterias ou computação embarcada — dependendo em vez disso de interações puramente mecânicas e energia ambiental. Os robôs coordenam comportamento emergente por meio de contato físico e mecanismos passivos com molas, inspirados em colônias de formigas e fungos mucilaginosos. A abordagem pode gerar sistemas de enxame de ultrabaixo custo para inspeção de escombros ou monitoramento ambiental em locais onde a eletrônica falharia.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/the-smartest-robots-ma.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["Robótica de Enxame","Robótica Mole","Pesquisa","Bioinspirада"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-04","title":"Atuador resiliente abre caminho para robôs macios prontos para o espaço","summary":"Um atuador recém-desenvolvido para robótica mole demonstrou a tolerância à radiação e a resiliência térmica necessárias para operar em ambientes espaciais. Ao contrário de sistemas rígidos, robôs macios podem se conformar a terrenos irregulares e lidar com objetos frágeis, tornando-os atraentes para exploração planetária. O atuador sobrevive ao vácuo, a variações de temperatura superiores a 200 °C e a doses de radiação relevantes para missões lunares e marcianas — aproximando sistemas robóticos macios implantáveis para ciência espacial de um passo a mais.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/new-actuator-could-boo.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-resilient-actuator-potential-space-ready.html","tags":["Robótica Espacial","Robótica Mole","Atuador","Exploração"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-05","title":"Robôs semelhantes a pássaros prometem maior manobrabilidade do que drones convencionais","summary":"Uma nova classe de robôs inspirados em aves imita a forma como os pássaros recontornam dinamicamente suas asas durante o voo para navegar em ambientes complexos e congestionados de forma muito mais eficaz do que drones quadrotores. Ao incorporar estruturas de asas com morfologia passiva e penas caudais, os robôs alcançam raios de curva mais estreitos e maior estabilidade ao pairar perto de obstáculos sem sensores ou atuadores adicionais. As demonstrações mostraram o sistema navegando em copas de florestas densas e interiores de edifícios desabados — ambientes onde drones padrão frequentemente falham.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/birdlike-robots-that-p.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["Drones","Bioinspirаdo","Robótica Aérea","Busca e Salvamento"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-06","title":"Estrutura de cinco níveis avalia robôs humanoides em mobilidade, manipulação e cognição","summary":"Pesquisadores propuseram um modelo de capacidade padronizado de cinco níveis para robôs humanoides, análogo aos níveis de autonomia de direção autônoma da SAE. A estrutura avalia robôs em mobilidade, manipulação dextral e tomada de decisão cognitiva — fornecendo uma linguagem comum para comparar produtos de empresas concorrentes. Atualmente, nenhum humanoide disponível comercialmente atinge o nível dois nos três eixos simultaneamente, destacando a lacuna entre as afirmações de marketing e a capacidade real.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/which-technical-capabi.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["Humanoide","Padrões","Benchmarking","Indústria"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-07","title":"Pulseira permite que amputados controlem uma mão robótica com movimentos naturais","summary":"Uma pulseira não invasiva usa eletromiografia de superfície e aprendizado de máquina para decodificar os movimentos de mão pretendidos a partir de sinais musculares residuais, permitindo que amputados controlem uma mão protética robótica em tempo real. Diferentemente de soluções implantadas, não requer cirurgia e se calibra para um novo usuário em menos de dez minutos. Nos testes, os participantes alcançaram mais de 90% de precisão em uma tarefa de destreza padronizada em sua primeira sessão, com comercialização prevista em dois anos.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/wristband-enables-wear.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["Próteses","Wearables","EMG","Reabilitação"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-08","title":"Gill Pratt: o momento comercial dos robôs humanoides finalmente chegou","summary":"Gill Pratt, CEO do Toyota Research Institute e ex-gerente de programa da DARPA responsável pelo desafio de robótica, afirma que a convergência de modelos de fundação, atuadores aprimorados e custos decrescentes de sensores trouxe os robôs humanoides a um genuíno ponto de inflexão comercial. Em uma entrevista abrangente à IEEE Spectrum, Pratt argumenta que a principal barreira restante não é o hardware, mas os dados — especificamente conjuntos de dados em grande escala de manipulação humana em ambientes diversos e não estruturados. Ele prevê que humanoides domésticos serão comercialmente viáveis em cinco anos.","image":"https://spectrum.ieee.org/media-library/a-smiling-bespectacled-bearded-man-kneels-posed-behind-a-robotic-torso.jpg?id=65446567&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/humanoid-robots-gill-pratt-darpa","tags":["Humanoide","AI","Indústria","DARPA"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-09","title":"AI reduz congestionamentos de robôs em armazéns, aumentando o throughput em 25%","summary":"Um sistema de aprendizado por reforço treinado para gerenciar a coordenação de múltiplos robôs em grandes centros de distribuição alcançou uma melhoria de 25% no throughput de pedidos ao redirecionar dinamicamente robôs em torno de congestionamentos. Sistemas tradicionais de gerenciamento de armazéns usam regras de roteamento estáticas que se degradam conforme a densidade de robôs aumenta; o sistema de AI se adapta em tempo real às condições mutáveis do piso. A tecnologia foi validada em simulação e depois implantada em uma instalação real com mais de 200 robôs móveis autônomos.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/warehouse-robots.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["Robôs de Armazém","Aprendizado por Reforço","Logística","AI"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-10","title":"Robôs autônomos de armazém aprendem diretamente com a experiência no chão de fábrica","summary":"Uma implantação em um fabricante europeu de peças automotivas mostra robôs autônomos melhorando o desempenho de tarefas aprendendo com a experiência no trabalho, em vez de rotinas pré-programadas. O sistema usa uma arquitetura de aprendizado contínuo que atualiza o comportamento dos robôs à noite com base nos dados operacionais do dia, sem retreinamento humano. Ao longo de seis meses, as taxas de erro na separação de caixas caíram 40% à medida que os robôs se adaptaram às mudanças no inventário — uma das primeiras implantações documentadas de aprendizado contínuo no chão de fábrica em escala.","image":"https://spectrum.ieee.org/media-library/robotic-arms-on-mobile-bases-sort-crates-on-a-conveyor-belt-in-a-warehouse.png?id=63907821&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-warehouse-robots","tags":["Robôs de Armazém","Aprendizado Contínuo","Manufatura","AI"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-11","title":"Robôs minúsculos andam sobre a água para investigar ecossistemas de superfície","summary":"Pesquisadores desenvolveram robôs na escala de milímetros inspirados em aranhas d'água que podem caminhar sobre a tensão superficial da água, permitindo a amostragem não invasiva de ecossistemas de superfície aquática. Os robôs usam pernas hidrofóbicas e distribuição de peso precisamente ajustada para evitar romper a superfície da água enquanto carregam sensores em miniatura. As aplicações potenciais incluem monitoramento da qualidade da água, detecção de derramamentos de petróleo e estudo da camada nêuston — a comunidade pouco compreendida de organismos que vivem na interface ar-água.","image":"https://images.unsplash.com/photo-1635070041078-e363dbe005cb?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2025/10/251003033930.htm","tags":["Robótica Mole","Pesquisa","Ambiental","Bioinspirаdo"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-12","title":"Cientistas criam robôs menores que um grão de areia capazes de \"pensar\"","summary":"Pesquisadores da Cornell fabricaram microrrobôs menores que um grão de areia que incorporam circuitos fotovoltaicos embarcados capazes de lógica computacional simples, permitindo que os dispositivos respondam a estímulos ambientais sem controle externo. Os robôs podem ser guiados opticamente e executar tomada de decisão básica — como se mover em direção a um gradiente químico — usando apenas energia de luz ambiente. O marco aproxima significativamente sistemas microrrobóticos sem fio para detecção biomédica e ambiental da implantação.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260105165815.htm","tags":["Microrrobótica","Pesquisa","Biomédico","Nanotecnologia"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-13","title":"O avanço do vale da estranheza: tornando rostos de robôs menos perturbadores","summary":"Cientistas identificaram os sinais perceptuais precisos que desencadeiam o efeito do vale da estranheza em rostos de robôs humanoides — e demonstraram que ajustes direcionados na textura da pele, no timing das microexpressões e nos padrões de movimento ocular podem quase inteiramente eliminar a resposta de desconforto. Os achados têm implicações imediatas para robôs sociais, avatares de telepresença e design de robôs humanoides, onde a aceitação do usuário é crítica para a adoção. A pesquisa envolveu estudos de neuroimagem de participantes interagindo com rostos de robôs reais e simulados.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260116035308.htm","tags":["Robótica Social","Interação Humano-Robô","Pesquisa","Design"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-14","title":"Robô com AI aprende a colher tomates com mais eficiência ao longo do tempo","summary":"Um robô agrícola equipado com um modelo visão-linguagem e aprendizado por reforço demonstrou melhoria contínua na eficiência de colheita de tomates ao longo de um ensaio em estufa de seis semanas. O robô inicialmente danificava cerca de 8% das frutas; ao final do ensaio, as taxas de dano caíram abaixo de 1% à medida que ele aprendia a modular a força de preensão com base em estimativas de maturidade de sua câmera. O trabalho destaca a agricultura como campo de prova para sistemas robóticos adaptativos em ambientes reais altamente variáveis.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["Robótica Agrícola","Aprendizado por Reforço","AI","Colheita"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-15","title":"Robôs de DNA podem entregar medicamentos e caçar vírus dentro do corpo humano","summary":"Cientistas desenvolveram nanorobôs baseados em DNA que navegam em ambientes biológicos, reconhecem alvos moleculares específicos e entregam cargas terapêuticas com precisão no nível celular. Os robôs exploram o pareamento de bases Watson-Crick como mecanismo de orientação para buscar marcadores de câncer ou proteínas virais antes de liberar sua carga de medicamento. Em modelos de camundongos, a tecnologia reduziu a carga tumoral em 60% em comparação com a administração sistêmica de medicamentos, representando um salto significativo na nanomedicina direcionada.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["Nanorobótica","Médico","Entrega de Medicamentos","Biotecnologia"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-16","title":"Robô movido a vento projetado para exploração de longa duração de ambientes hostis","summary":"Um novo protótipo de robô movido a vento pode atravessar terrenos desafiadores por meses sem baterias ou combustível, colhendo energia diretamente do fluxo de ar ambiente por meio de um mecanismo passivo de vela e mola. O design tem como alvo ambientes hostis a robôs convencionais — calotas polares, desertos áridos, zonas pós-desastre — onde o reabastecimento é impossível. Os primeiros testes de campo mostraram locomoção sustentada em um percurso desértico rochoso por 48 horas sem intervenção humana.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/wind-powered-robot-cou.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-powered-robot-enable-term-exploration.html","tags":["Coleta de Energia","Robótica de Campo","Pesquisa","Exploração"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-17","title":"Chip Wi-Fi endurecido contra radiação abre porta para robôs de descomissionamento nuclear","summary":"Engenheiros projetaram um chip Wi-Fi capaz de sobreviver a doses de radiação de até 500 kiloGrays — cerca de 500 vezes a dose que destrói eletrônicos de consumo convencionais — tornando viável pela primeira vez o controle sem fio robusto de robôs de descomissionamento nuclear. Os robôs atuais em instalações como Fukushima e Sellafield devem usar comunicações com fio ou fortemente blindadas que limitam alcance e manobrabilidade. O novo chip usa geometrias de transistores tolerantes à radiação e hardware de correção de erros para manter links de dados confiáveis em ambientes de alto fluxo.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/radiation-resistant-wi.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-radiationhardened-wifi-chip-survives-kgy.html","tags":["Nuclear","Sensores","Eletrônica","Descomissionamento"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-18","title":"Robôs enfrentam o calor na manutenção de fazendas solares em escala utilitária","summary":"Robôs especializados de inspeção e limpeza estão agora realizando tarefas de manutenção perigosas em grandes instalações solares, substituindo equipes que antes trabalhavam em temperaturas superiores a 50 °C em locais desérticos. Os robôs usam visão computacional para identificar painéis danificados, limpar acúmulo de poeira e realizar pequenos reparos em cabos. As primeiras implantações no Oriente Médio e no Arizona mostram melhorias de 15 a 20% na produção anual dos painéis, com uma equipe de robôs substituindo quatro técnicos humanos a um quarto do custo anual.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/robots-take-the-heat-f.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["Energia Solar","Robôs Industriais","Inspeção","Clima"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-19","title":"Músculos artificiais pneumáticos ajudam robôs a levantar 100 vezes seu próprio peso","summary":"Um novo design de músculo artificial pneumático alcança uma relação força-peso que permite aos robôs levantar cargas 100 vezes sua própria massa — superando em muito a maioria dos sistemas acionados por motores elétricos em escala comparável. Os músculos usam uma geometria de dobras em acordeão inovadora em um polímero de alta resistência que armazena energia sob compressão e a libera rapidamente. O design é especialmente promissor para robôs com pernas e exoesqueletos onde eficiência energética e densidade de potência são críticas.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/air-powered-artificial.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-air-powered-artificial-muscles-robots.html","tags":["Atuador","Robótica Mole","Exoesqueleto","Pneumática"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-20","title":"Desafio de Triagem DARPA enfrenta equipes de robôs contra cenários de múltiplas vítimas","summary":"O Desafio de Triagem da DARPA reuniu equipes de robôs autônomos encarregadas de localizar, avaliar e priorizar vítimas feridas em um campo de batalha simulado — inteiramente sem direção humana. Os sistemas concorrentes usaram câmeras térmicas, radar de penetração no solo e algoritmos de triagem de AI para identificar e reportar vítimas. A equipe vencedora processou um cenário de 40 vítimas em menos de 12 minutos — uma tarefa que normalmente leva uma equipe médica humana mais de uma hora — enquanto a DARPA tem como alvo sistemas totalmente autônomos de assistência a vítimas na linha de frente até 2030.","image":"https://spectrum.ieee.org/media-library/aerial-drone-robotic-arm-explosion-and-medical-cross-on-abstract-background.jpg?id=62605094&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/darpa-triage-challenge-robots","tags":["DARPA","Robôs Médicos","Autônomo","Defesa"],"timestamp":"2026-04-07T02:29:52Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-06"] = {"date":"2026-04-06","featured":{"id":"featured-0406","title":"Boston Dynamics Spot vira objeto de estudo: cientistas investigam a interação social humano-robô","summary":"Pesquisadores estão estudando como famílias e visitantes interagem com o robô Spot da Boston Dynamics no Robotics & AI Institute, revelando insights surpreendentes sobre o conforto e a confiança humana em relação a máquinas quadrúpedes. O estudo mostra que crianças se adaptam mais rápido do que adultos e que sinais visuais no corpo do robô afetam significativamente a simpatia percebida.","image":"https://spectrum.ieee.org/media-library/families-watch-a-colorful-robotic-dog-demo-at-a-robotics-and-ai-institute-exhibit.jpg?id=65453180&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/boston-dynamics-spot-interaction","tags":["Boston Dynamics","HRI","Robótica Social"],"timestamp":"2026-04-06T13:00:01Z"},"articles":[{"id":"0406-001","title":"Atuador resistente mostra potencial para robôs macios prontos para o espaço","summary":"Um novo design de atuador suporta pressões, temperaturas e radiações extremas, tornando-o adequado para implantar robôs macios no espaço exterior, no fundo do oceano e em ambientes nucleares. A pesquisa abre caminhos para que robôs operem em locais antes inacessíveis a máquinas rígidas convencionais.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-resilient-actuator-potential-space-ready.html","tags":["Robótica Macia","Espaço","Atuador"],"timestamp":"2026-04-05T10:00:03Z"},{"id":"0406-002","title":"Vídeo da Sexta: Digit aprende a dançar praticamente do dia para a noite","summary":"No Vídeo da Sexta desta semana, o robô humanoide Digit da Agility Robotics demonstra novos movimentos de dança aprendidos em simulação e transferidos para o mundo real em menos de 24 horas — sinal do rápido amadurecimento das técnicas de transferência sim-to-real.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/video-humanoid-dancing","video":"https://www.youtube.com/watch?v=29ECwExc-_M","tags":["Agility Robotics","Digit","Dança","Sim-to-Real"],"timestamp":"2026-04-03T16:30:01Z"},{"id":"0406-003","title":"MirrorBot: um robô projetado para estimular a conexão humana","summary":"Pesquisadores da Cornell University apresentaram o MirrorBot, um robô que espelha a linguagem corporal e os sinais emocionais humanos para criar uma sensação de empatia e conexão. Os primeiros testes mostram que os participantes se sentiram mais compreendidos e menos isolados após interagir com o MirrorBot.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-mirrorbot-robot-foster-human.html","tags":["Robôs Sociais","Cornell","HRI"],"timestamp":"2026-04-02T17:00:10Z"},{"id":"0406-004","title":"Músculos artificiais pneumáticos podem ajudar robôs a levantar 100 vezes seu peso","summary":"Pesquisadores da Arizona State University estão desenvolvendo músculos robóticos pneumáticos bioinspiradores que permitem aos robôs levantar objetos de até 100 vezes seu próprio peso enquanto operam em ambientes extremos, incluindo água fervendo e superfícies altamente abrasivas.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-air-powered-artificial-muscles-robots.html","tags":["Músculos Artificiais","Robótica Macia","Arizona State"],"timestamp":"2026-04-02T11:20:06Z"},{"id":"0406-005","title":"Pesquisadores criam enxame robótico sem eletrônica, sem baterias e sem cérebros","summary":"Uma equipe da Georgia Tech criou um enxame robótico mecânico que alcança comportamento coletivo coordenado usando interações puramente físicas — sem sensores, sem processadores, sem baterias. O design inspirado no LEGO demonstra que comportamento inteligente de grupo pode emergir de simples regras mecânicas.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["Robótica de Enxame","Georgia Tech","Mecânica"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0406-006","title":"Combinando o Robot Operating System com LLMs para controle de robôs por linguagem natural","summary":"Uma nova pesquisa integra Grandes Modelos de Linguagem diretamente ao ROS (Robot Operating System), permitindo que operadores comandem robôs usando frases em inglês comum. O sistema traduz instruções em linguagem natural em sequências de ações ROS em tempo real, reduzindo drasticamente a barreira de programação robótica.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-combining-robot-llms-natural-language.html","tags":["ROS","LLM","Linguagem Natural","Controle"],"timestamp":"2026-04-01T08:10:01Z"},{"id":"0406-007","title":"Gill Pratt diz que o momento dos robôs humanoides finalmente chegou","summary":"Gill Pratt, CEO do Toyota Research Institute e ex-gerente do programa de robótica da DARPA, argumenta em uma nova entrevista para a IEEE Spectrum que a confluência de IA melhorada, atuadores mais baratos e baterias aprimoradas finalmente criou condições para que robôs humanoides entreguem valor econômico real.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/humanoid-robots-gill-pratt-darpa","tags":["Humanoide","DARPA","Toyota","Análise Setorial"],"timestamp":"2026-04-02T15:00:02Z"},{"id":"0406-008","title":"Wi-Fi que resiste a um reator nuclear — para robôs de descomissionamento","summary":"Um chip Wi-Fi endurecido contra radiação, capaz de sobreviver a 500 kGy, foi desenvolvido especificamente para robôs usados no descomissionamento de usinas nucleares. O chip permite comunicação sem fio em tempo real mesmo dentro de núcleos de reatores ativos, eliminando a necessidade de cabos.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/robotics-in-nuclear-industry","tags":["Nuclear","Radiação","Wi-Fi","Industrial"],"timestamp":"2026-04-02T14:00:02Z"},{"id":"0406-009","title":"Cientistas criam robôs vivos com sistemas nervosos","summary":"Pesquisadores criaram o «NeuroBot» — robôs vivos montados a partir de células biológicas que incluem estruturas funcionais semelhantes ao sistema nervoso. Esses organismos conseguem perceber o ambiente e gerar padrões de locomoção coordenados, borrando a fronteira entre robô e organismo.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/neurobot-living-robot-nervous-system","tags":["Biohíbrido","Robôs Vivos","Neurociência"],"timestamp":"2026-04-02T13:00:01Z"},{"id":"0406-010","title":"Framework de controle permite que robôs flexíveis se movam em espaços apertados com menos matemática","summary":"Um novo framework de controle simplifica drasticamente o planejamento de trajetórias para robôs contínuos e flexíveis que operam em espaços confinados como canos, vasos sanguíneos e prédios desabados. A abordagem reduz o tempo de computação em 80% em comparação com os métodos atuais, mantendo a precisão de navegação.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["Robôs Contínuos","Planejamento de Trajetórias","Controle"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0406-011","title":"Perguntas & Respostas: robôs não conseguem sentir — mas novos sensores de pressão podem mudar isso","summary":"O pesquisador da Penn State Huanyu Cheng explica como uma nova classe de sensores de pressão flexíveis poderia dar aos robôs um sentido do tato comparável ao da pele humana. Os sensores conseguem detectar texturas, temperaturas e níveis de força simultaneamente — um passo em direção a mãos robóticas verdadeiramente táteis.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-qa-robots-sensors.html","tags":["Percepção Tátil","Penn State","Mãos Robóticas"],"timestamp":"2026-03-30T17:00:04Z"},{"id":"0406-012","title":"Robôs com corpos diferentes agora podem compartilhar habilidades por meio de aprendizado baseado em intenções","summary":"Um novo framework de aprendizado de máquina permite que robôs com corpos físicos completamente diferentes compartilhem conhecimento de tarefas ao abstrair habilidades em «intenções» em vez de comandos motores. Um braço robótico e um humanoide podem aprender da mesma demonstração sem retreinamento específico para cada corpo.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-bodies-skills-intention-based.html","tags":["Aprendizado por Transferência","Cross-Embodiment","AI"],"timestamp":"2026-03-30T13:20:04Z"},{"id":"0406-013","title":"HEAPGrasp: uma forma mais rápida e inteligente para robôs lidarem com objetos difíceis","summary":"HEAPGrasp é um novo algoritmo de preensão que combina planejamento hierárquico com feedback háptico em tempo real para robôs agarrarem de forma confiável objetos de forma irregular, escorregadios ou deformáveis. Em testes em armazém, atingiu 97,3% de taxa de sucesso em itens nunca vistos antes.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-heapgrasp-faster-smarter-robots-tricky.html","tags":["Preensão","Manipulação","Armazém"],"timestamp":"2026-03-30T11:20:03Z"},{"id":"0406-014","title":"Benchmark de IA ajuda robôs a planejar e concluir tarefas domésticas no mundo real","summary":"Um novo benchmark padronizado chamado HomeTask-3000 avalia quão bem robôs domésticos conseguem planejar e executar tarefas de múltiplas etapas em ambientes domésticos realistas. O conjunto inclui 3.000 cenários de tarefas em 47 layouts de casa, oferecendo a avaliação mais rigorosa de robôs no mundo real até hoje.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-benchmark-robots-chores-real.html","tags":["Benchmark","Robôs Domésticos","Planejamento com IA"],"timestamp":"2026-03-29T11:30:02Z"},{"id":"0406-015","title":"IA baseada em vídeo dá aos robôs uma imaginação visual","summary":"Yilun Du, do Harvard Kempner Institute, apresenta um sistema que permite aos robôs «imaginar» o resultado visual de suas ações antes de executá-las, usando um modelo de geração de vídeo como modelo de mundo. Robôs treinados com essa imaginação visual resolvem tarefas de manipulação 40% mais eficientemente.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-video-based-ai-robots-visual.html","tags":["Modelo de Mundo","IA Visual","Harvard","Manipulação"],"timestamp":"2026-03-26T10:20:03Z"},{"id":"0406-016","title":"Sistema de IA evita congestionamento de robôs em armazéns e aumenta o throughput em 25%","summary":"Um novo sistema de aprendizado por reforço multi-agente redireciona dinamicamente frotas de robôs em armazéns para evitar pontos de congestionamento, alcançando aumento de 25% no throughput de pedidos. O sistema foi validado em uma simulação de um centro de distribuição da Amazon com 500 robôs.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["Armazém","Multi-Agente","Aprendizado por Reforço"],"timestamp":"2026-03-26T09:30:01Z"},{"id":"0406-017","title":"Ultrassom inspirado em morcegos ajuda drones do tamanho de uma palma a navegar em névoa e fumaça","summary":"Pesquisadores da WPI equiparam drones do tamanho de uma palma com sensores ultrassônicos bioinspiradores e um sistema de IA que permite navegação autônoma em condições de visibilidade zero. O sistema supera a navegação baseada em câmera em ambientes com fumaça, abrindo aplicações para drones de resgate em incêndios.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ultrasound-palm-sized-drones-fog.html","tags":["Drones","Ultrassom","Navegação","WPI"],"timestamp":"2026-03-26T09:06:49Z"},{"id":"0406-018","title":"Novo drone policial da BRINC usa Starlink, carrega Narcan e persegue veículos a 100 km/h","summary":"A empresa de robótica de defesa BRINC revelou o Guardian, descrito como «o drone de resposta 911 mais capaz já criado». Ele se conecta via Starlink para cobertura nacional, pode implantar um dispensador de Narcan para respostas a overdoses e persegue veículos em fuga a até 100 km/h.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"Ars Technica","url":"https://arstechnica.com/gadgets/2026/03/brincs-new-police-drone-uses-starlink-carries-narcan-chases-vehicles-at-60mph/","tags":["Polícia","Drone","Starlink","BRINC"],"timestamp":"2026-03-25T21:12:03Z"},{"id":"0406-019","title":"Robôs suportam o calor pelos humanos na manutenção das maiores fazendas solares da Austrália","summary":"Robôs de inspeção movidos por IA estão sendo implantados nas grandes fazendas solares da Austrália para substituir o perigoso trabalho humano de manutenção no extremo calor do interior. Os robôs percorrem autonomamente quilômetros de terreno desértico irregular para limpar painéis, detectar falhas e realizar reparos menores.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["Solar","Inspeção","Austrália","Industrial"],"timestamp":"2026-03-25T18:10:07Z"},{"id":"0406-020","title":"FedEx escolhe parcerias em vez de tecnologia proprietária para sua estratégia de automação","summary":"A FedEx anunciou uma grande parceria com a Berkshire Gray para implantar robôs de triagem e manipulação movidos por IA em sua rede, sinalizando o giro estratégico da empresa de desenvolver robótica internamente para uma abordagem de ecossistema com os melhores fornecedores do mercado.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","Logística","Automação","Berkshire Gray"],"timestamp":"2026-03-31T15:46:50Z"},{"id":"0406-021","title":"Nomadic levanta US$ 8,4 milhões para organizar os dados gerados por veículos autônomos","summary":"A startup Nomadic levantou US$ 8,4 milhões para construir infraestrutura que converte gravações de sensores de robôs e veículos autônomos em conjuntos de dados estruturados e pesquisáveis usando deep learning. A empresa mira um grande gargalo no desenvolvimento de sistemas autônomos: processamento e rotulagem de dados em escala.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["Startup","Financiamento","Veículos Autônomos","Dados"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0406-022","title":"Pulseira permite que usuários controlem uma mão robótica com seus próprios movimentos","summary":"Uma nova pulseira EMG desenvolvida por pesquisadores do MIT lê sinais musculares do antebraço para fornecer controle intuitivo em tempo real de uma prótese de mão robótica. Os usuários conseguem controlar movimentos de dedos individuais com menos de 20 horas de treinamento, uma melhoria dramática em relação às próteses mioeléctricas existentes.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["Próteses","EMG","MIT","Wearable"],"timestamp":"2026-03-25T06:00:09Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-05"] = {"date":"2026-04-05","featured":{"id":"featured-20260405","title":"Cientistas constroem robôs vivos com sistemas nervosos","summary":"Pesquisadores criaram o 'NeuroBot' — robôs vivos montados a partir de células biológicas que incluem estruturas funcionais semelhantes ao sistema nervoso, capazes de detectar e gerar movimentos coordenados. Os resultados, publicados na Nature, apagam a fronteira entre o robô de engenharia e o organismo vivo.","image":"https://spectrum.ieee.org/media-library/close-up-of-a-neuro-robot-that-has-been-stained-to-highlight-multi-ciliated-cells-around-its-periphery.jpg?id=65444408&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/neurobot-living-robot-nervous-system","tags":["Robôs vivos","Biohíbrido","Nature"],"timestamp":"2026-04-02T13:00:01Z"},"articles":[{"id":"0405-001","title":"Gill Pratt afirma que o momento dos robôs humanoides finalmente chegou","summary":"Gill Pratt, CEO do Toyota Research Institute e ex-gerente do programa de robótica da DARPA, argumenta em uma nova entrevista à IEEE Spectrum que a confluência de IA mais avançada, atuadores mais baratos e baterias melhoradas criou as condições para que os robôs humanoides gerem valor econômico real pela primeira vez.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/humanoid-robots-gill-pratt-darpa","tags":["Humanoide","Toyota","DARPA","Análise de indústria"],"timestamp":"2026-04-02T15:00:02Z"},{"id":"featured-0405","title":"Estudo sobre as atitudes humanas em relação aos robôs por meio da experiência real com o Boston Dynamics Spot","summary":"Um estudo marcante realizado no Robotics & AI Institute acompanhou durante seis meses como centenas de famílias interagiram com o Spot da Boston Dynamics, revelando padrões de confiança, medo e antropomorfização. Os dados estão reformulando a abordagem dos designers quanto à estética e ao comportamento social dos robôs.","image":"https://spectrum.ieee.org/media-library/families-watch-a-colorful-robotic-dog-demo-at-a-robotics-and-ai-institute-exhibit.jpg?id=65453180&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/boston-dynamics-spot-interaction","tags":["Boston Dynamics","HRI","Pesquisa de usuários"],"timestamp":"2026-04-05T13:00:01Z"},{"id":"0405-003","title":"Physical Intelligence estaria em negociações para captar mais US$ 1 bilhão","summary":"Physical Intelligence (π), a startup de aprendizado robótico de propósito geral, estaria em negociações avançadas para captar US$ 1 bilhão, o que efetivamente dobraria sua avaliação de US$ 5,6 bilhões em apenas quatro meses. O modelo fundacional π0 da empresa foi licenciado para múltiplos fabricantes OEM de robôs.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","Captação","Modelo fundacional"],"timestamp":"2026-03-27T23:59:40Z"},{"id":"0405-004","title":"Vivo ou não? Pequenos robôs impressos em 3D que nadam e navegam como animais","summary":"A professora Daniela Kraft e Mengshi Wei, da Leiden University, criaram robôs microscópicos que se movem sem sensores, software ou controle externo. Seu comportamento emerge inteiramente da geometria física e das propriedades dos materiais, imitando como organismos aquáticos simples navegam.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["Microrrobôs","Impressão 3D","Leiden University"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0405-005","title":"Vídeo de Sexta: o robô bípede Roadrunner quebra o molde","summary":"O Vídeo de Sexta desta semana destaca o Roadrunner, um inovador robô bípede que usa um sistema de locomoção híbrido com rodas para atingir velocidades de até 5 m/s em terreno plano, mantendo estabilidade em escadas e terrenos irregulares — uma ruptura fundamental com o design clássico de robôs que caminham.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/roadrunner-bipedal-robot","video":"https://www.youtube.com/watch?v=tF4DML7FIWk","tags":["Bípede","Locomoção","Velocidade"],"timestamp":"2026-03-27T16:30:03Z"},{"id":"0405-006","title":"Gêmeos digitais para robôs de resgate: o que o processamento mais rápido de nuvens de pontos 3D possibilita","summary":"Novos algoritmos reduzem o tempo de processamento de nuvens de pontos 3D de segundos para milissegundos, permitindo que robôs construam e atualizem mapas de gêmeos digitais do ambiente em tempo real. O avanço é essencial para robôs de resgate que navegam em estruturas desabadas onde as condições mudam dinamicamente.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-digital-twins-robots-faster-3d.html","tags":["Gêmeo digital","Mapeamento 3D","Busca e resgate"],"timestamp":"2026-03-26T15:50:01Z"},{"id":"0405-007","title":"Melania Trump quer um robô para educar seu filho em casa","summary":"A Primeira-Dama endossou o robô humanoide da Figure AI como potencial tutor doméstico movido por IA, imaginando robôs que personalizam o currículo e oferecem instrução individual. Os comentários geraram amplo debate sobre o uso de robôs na educação e no desenvolvimento infantil.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/melania-trump-wants-a-robot-to-homeschool-your-child/","tags":["Figure AI","Educação","Humanoide"],"timestamp":"2026-03-25T18:55:41Z"},{"id":"0405-008","title":"Lucid Bots capta R$ 20 milhões para atender à demanda por seus drones lava-janelas","summary":"A Lucid Bots, fabricante de drones autônomos que limpam janelas de arranha-céus e lavam fachadas de edifícios com jato de alta pressão, captou US$ 20 milhões em uma Série B para escalar a produção. A demanda se acelerou à medida que os proprietários de edifícios enfrentam custos crescentes de mão de obra para manutenção perigosa em grandes alturas.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/lucid-bots-raises-20m-to-keep-up-with-demand-for-its-window-washing-drones/","tags":["Drones","Startup","Captação","Limpeza"],"timestamp":"2026-03-25T11:00:00Z"},{"id":"0405-009","title":"Amazon adquire a Fauna Robotics, fabricante do robô humanoide Sprout","summary":"A Amazon adquiriu a Fauna Robotics, a startup por trás do Sprout — um humanoide amigável de tamanho infantil projetado para espaços sociais como casas e hospitais. A aquisição, a segunda compra de robótica da Amazon este mês, sinaliza o avanço da empresa na robótica doméstica e de saúde.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/amazon-just-bought-a-startup-making-kid-size-humanoid-robots/","tags":["Amazon","Aquisição","Humanoide","Fauna Robotics"],"timestamp":"2026-03-25T00:53:39Z"},{"id":"0405-010","title":"Agile Robots faz parceria com Google DeepMind para integrar modelos fundacionais","summary":"A empresa de robótica germano-chinesa Agile Robots assinou uma parceria com o Google DeepMind para integrar modelos fundacionais de robótica em suas plataformas humanoides. Em troca, a Agile Robots contribuirá com dados de demonstração de tarefas do mundo real para os conjuntos de treinamento do DeepMind.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/agile-robots-becomes-the-latest-robotics-company-to-partner-with-google-deepmind/","tags":["Agile Robots","Google DeepMind","Modelo fundacional"],"timestamp":"2026-03-24T12:05:00Z"},{"id":"0405-011","title":"Drones combinados com IA podem ajudar equipes de busca e resgate a encontrar pessoas desaparecidas mais rápido","summary":"Um sistema de drones multissensor que combina câmeras infravermelha, térmica e colorida com um sistema de análise por IA pode acelerar drasticamente as operações de busca e resgate. Testes de campo mostraram que o sistema localiza pessoas desaparecidas até 4 vezes mais rápido do que equipes terrestres sozinhas.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-drones-paired-ai-searchandrescue-teams.html","tags":["Drones","Busca e resgate","Imagem térmica"],"timestamp":"2026-03-24T14:20:05Z"},{"id":"0405-012","title":"Modelo de cinco níveis classifica robôs humanoides em mobilidade, manipulação e cognição","summary":"Pesquisadores do Fraunhofer HNFIZ publicaram um novo framework de avaliação padronizado que classifica os robôs humanoides em cinco níveis de capacidade segundo mobilidade, destreza de manipulação e autonomia cognitiva — semelhante aos níveis SAE para veículos autônomos.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["Humanoide","Fraunhofer","Padrões","Avaliação"],"timestamp":"2026-03-23T17:20:07Z"},{"id":"0405-013","title":"Robôs inspirados em pássaros prometem maior flexibilidade e controle que drones","summary":"Engenheiros da Rutgers University criaram um robô de asas batentes inspirado em pássaros cujas asas se dobram e giram em tempo real para lidar com ventos cruzados e turbulência. O design atinge uma eficiência energética 3 vezes melhor que drones quadrirotores equivalentes em baixas velocidades.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["Asas batentes","Bio-inspirado","Rutgers","Drones"],"timestamp":"2026-03-23T13:20:02Z"},{"id":"0405-014","title":"Robô inspirado em insetos rastreia odores mesmo com apenas uma 'antena' funcionando","summary":"Um robô bio-inspirado modelado nos sistemas olfativos de insetos consegue localizar fontes de odores — vazamentos de gás, explosivos, pessoas desaparecidas — tanto em ambientes internos quanto externos. O sistema mantém precisão consistente mesmo quando uma das duas unidades de sensores falha, uma característica crítica para implantação no mundo real.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-insect-robot-tracks-odors-antenna.html","tags":["Olfativo","Bio-inspirado","Robô de busca"],"timestamp":"2026-03-23T12:00:03Z"},{"id":"0405-015","title":"Chip Wi-Fi resistente à radiação sobrevive a 500 kGy para robôs de descomissionamento nuclear","summary":"Um novo chip Wi-Fi resistente à radiação, projetado para robôs de descomissionamento de usinas nucleares, consegue sobreviver a 500 kilograys de radiação ionizante — equivalente a 250 milhões de radiografias dentárias. O chip permite o controle sem fio de robôs dentro de reatores ativos, substituindo os perigosos sistemas de cabos.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-radiationhardened-wifi-chip-survives-kgy.html","tags":["Nuclear","Radiação","Wi-Fi","Descomissionamento"],"timestamp":"2026-03-23T13:00:09Z"},{"id":"0405-016","title":"Como tutores robóticos de Chicago ensinam aprendizado socioemocional sem fingir ser humanos","summary":"Em salas de aula do quarto ano em Chicago, robôs ensinam empatia e resolução de conflitos sendo transparentes sobre sua natureza de máquinas. A abordagem evita o 'vale da estranheza' das interações excessivamente humanoides e alcança melhores resultados de aprendizado ao manter limites claros entre robô e aluno.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-chicago-robot-sel-effectively-human.html","tags":["Educação","Robôs sociais","SEL","Chicago"],"timestamp":"2026-03-20T06:10:01Z"},{"id":"0405-017","title":"Mais inteligente, mais rápido, mais humano: sistema de IA ajuda robôs a superar seus professores humanos","summary":"Um novo framework de aprendizado por imitação permite que robôs não apenas repliquem tarefas demonstradas, mas as melhorem — executando movimentos aprendidos até 30% mais rápido que o demonstrador humano após apenas 10 ensaios de prática. A chave é um sistema de IA que identifica e elimina ineficiências nas demonstrações humanas.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-smarter-faster-human-ai-robots.html","tags":["Aprendizado por imitação","Aprendizado robótico","AI"],"timestamp":"2026-03-19T14:20:06Z"},{"id":"0405-018","title":"Robô movido a vento permite exploração de longa duração em ambientes hostis","summary":"O WANDER-bot da Cranfield University é um robô de baixo custo impresso em 3D, alimentado inteiramente por energia eólica, projetado para monitoramento autônomo de longa duração em desertos, tundras e regiões vulcânicas. Sem baterias ou painéis solares, o WANDER-bot pode operar indefinidamente em ambientes ventosos.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-powered-robot-enable-term-exploration.html","tags":["Energia eólica","Exploração","Cranfield","Energia"],"timestamp":"2026-03-19T16:20:03Z"},{"id":"0405-019","title":"Há 30 anos, robôs aprenderam a andar sem cair — o P2 da Honda é nomeado marco IEEE","summary":"O IEEE designou o robô humanoide P2 da Honda — apresentado em 1996 — como marco oficial IEEE, reconhecendo-o como o primeiro bípede autônomo a demonstrar caminhada dinâmica confiável. O P2 estabeleceu a base técnica de praticamente todos os robôs que caminham depois dele.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/honda-p2-robot-ieee-milestone","tags":["Honda","História","IEEE","Bípede"],"timestamp":"2026-03-25T18:00:05Z"},{"id":"0405-020","title":"Robô com IA aprende a colher tomates com mais eficiência prevendo a dificuldade","summary":"Um novo robô colhedor de tomates não apenas identifica frutos maduros — ele prevê o quão difícil será colher cada tomate com base no ângulo do caule, na densidade do cacho e na oclusão de folhas, priorizando os alvos mais fáceis. Essa estratégia 'consciente da dificuldade' aumentou o rendimento da colheita em 35% em ensaios em estufa.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["AgriRobótica","Colheita","Planejamento com AI"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0405-021","title":"Robôs de DNA podem entregar medicamentos e caçar vírus dentro do seu corpo","summary":"Pesquisadores estão desenvolvendo robôs nanoscópicos baseados em DNA que podem navegar pela corrente sanguínea, identificar células-alvo e liberar cargas terapêuticas. Essas máquinas programáveis emprestam conceitos da robótica tradicional — locomoção, detecção, atuação — mas operam na escala molecular.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["Nanorobôs","Médico","DNA","Entrega de medicamentos"],"timestamp":"2026-03-31T07:16:58Z"},{"id":"0405-022","title":"Gecko Robotics assina o maior contrato de robótica da Marinha dos EUA até hoje","summary":"A Gecko Robotics assinou um contrato de cinco anos com a Marinha dos EUA para monitorar e prever necessidades de manutenção em toda a frota naval usando robôs de inspeção que escalam paredes, equipados com sensores de ultrassom. O contrato é o maior da história da Marinha dos EUA na área de robótica.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["Militar","Marinha","Inspeção","Gecko Robotics"],"timestamp":"2026-03-17T10:00:00Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-04"] = {"date":"2026-04-04","featured":{"id":"featured-0404","title":"Vídeo de Sexta: Digit aprende a dançar quase da noite para o dia","summary":"O humanoide Digit da Agility Robotics aprendeu rotinas complexas de dança sincronizada usando um novo pipeline de transferência simulação-para-real que comprime o treinamento de semanas para horas. A demo exibe movimentos fluidos e sincronizados com a música, empurrando os limites atuais do controle de locomoção em robôs humanoides.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=1200&h=600&fit=crop","video":"https://www.youtube.com/watch?v=29ECwExc-_M","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/video-humanoid-dancing","tags":["Agility Robotics","Digit","Locomoção"],"timestamp":"2026-04-03T16:30:01Z"},"articles":[{"id":"0404-001","title":"Você confia em mim? Um framework para tornar redes de robôs e veículos mais seguras","summary":"Um novo framework de confiança computacional permite que redes heterogêneas de robôs e veículos autônomos avaliem dinamicamente a confiabilidade de seus pares e ajustem estratégias de coordenação. O sistema reduz o risco de colisão em ambientes multi-robô em 62% na simulação.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-framework-networks-robots-vehicles-safer.html","tags":["Confiança","Multi-Robô","Segurança","Veículos Autônomos"],"timestamp":"2026-04-02T14:20:01Z"},{"id":"0404-002","title":"Funcionários tiveram que conter um robô humanoide dançarino que saiu do controle em restaurante na Califórnia","summary":"Um restaurante Haidilao de hot pot em Cupertino viralizou depois que seu garçom humanoide AgiBot começou a dançar de forma descontrolada, exigindo intervenção da equipe. O incidente, gravado por vários smartphones, reacendeu discussões sobre a robustez de sistemas de IA e a dependência excessiva de automação em ambientes com atendimento ao público.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/restaurant-dancing-robot-went-wild-hot-pot-cupertino-haidilao-agibot/","tags":["AgiBot","Restaurante","Incidente","Viral"],"timestamp":"2026-03-19T21:13:50Z"},{"id":"0404-003","title":"Rover Perseverance bate recorde de condução autônoma em Marte","summary":"O rover Perseverance da NASA estabeleceu um novo recorde de condução autônoma em Marte, cobrindo 699 metros em um único sol com seu sistema AutoNav. A conquista demonstra planejamento de rotas por IA aprimorado, navegando ao redor de obstáculos sem aguardar comandos da Terra.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/perseverance-mars-rover-autonomous-driving","tags":["NASA","Marte","Autônomo","Perseverance"],"timestamp":"2026-02-25T15:00:02Z"},{"id":"0404-004","title":"Mão robótica sem motores: como funciona um atuador de mudança de forma em menos de um segundo","summary":"Pesquisadores desenvolveram uma mão robótica sem motor, atuada inteiramente por fios de liga com memória de forma que mudam de configuração em menos de um segundo. O design é 70% mais leve que os equivalentes com motor, um avanço para próteses e braços robóticos espaciais de baixo peso.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["Liga com Memória de Forma","Próteses","Atuador"],"timestamp":"2026-03-25T10:00:04Z"},{"id":"0404-005","title":"Mind Robotics, spinout da Rivian, capta 500 milhões de dólares para robôs industriais com IA","summary":"A Mind Robotics, startup criada pelo fundador da Rivian, RJ Scaringe, fechou uma Série A de 500 milhões de dólares. A empresa desenvolve robôs industriais com IA que aprendem com o ambiente fabril da Rivian e mira disponibilidade comercial até 2027.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/rivian-mind-robotics-series-a-500m-fund-raise-industrial-ai-powered-robots/","tags":["Rivian","Startup","Captação","Industrial"],"timestamp":"2026-03-11T16:12:02Z"},{"id":"0404-006","title":"Rede neural artificial reproduz padrões de marcha de animais de quatro patas","summary":"Pesquisadores suíços construíram uma rede neural que replica com precisão os padrões de andar, trotar e galopar de cavalos, cães e gatos, incluindo transições automáticas de marcha em resposta a mudanças de velocidade. O modelo está sendo usado para melhorar a locomoção de robôs quadrúpedes.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-artificial-neural-network-gait-patterns.html","tags":["Quadrúpede","Locomoção","Rede Neural","Bio-Inspirado"],"timestamp":"2026-03-23T17:20:08Z"},{"id":"0404-007","title":"RJ Scaringe, da Rivian, acha que estamos errando em robótica","summary":"Em entrevista exclusiva, o CEO da Rivian, RJ Scaringe, argumenta que o setor de robótica está focado demais em replicar a forma humana em vez de projetar máquinas para tarefas específicas. Sua nova startup Mind Robotics adota uma abordagem fundamentalmente diferente para a automação industrial.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/15/rivians-rj-scaringe-thinks-were-doing-robots-all-wrong/","tags":["Mind Robotics","Rivian","Opinião","Indústria"],"timestamp":"2026-03-15T14:30:00Z"},{"id":"0404-008","title":"Por que a indústria chinesa de robôs humanoides está dominando o mercado inicial","summary":"Análise da TechCrunch revela que fabricantes chineses de robôs humanoides estão entregando mais unidades e iterando mais rápido do que concorrentes americanos. Empresas como Unitree, UBTech, Fourier Intelligence e Engine AI implantaram comercialmente mais humanoides do que todas as empresas ocidentais juntas.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/28/why-chinas-humanoid-robot-industry-is-winning-the-early-market/","tags":["China","Humanoide","Análise de Mercado","Unitree"],"timestamp":"2026-02-28T15:00:00Z"},{"id":"0404-009","title":"Parceria da Qualcomm com Neura Robotics sinaliza avanço de fabricantes de chips em humanoides","summary":"A Qualcomm fechou parceria com a startup alemã de humanoides Neura Robotics para construir robôs de próxima geração usando seus processadores de IA IQ10. A parceria marca a entrada mais significativa da Qualcomm em IA incorporada e hardware humanoide, competindo com a plataforma robótica da Nvidia.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/09/qualcomms-partnership-with-neura-robotics-is-just-the-beginning/","tags":["Qualcomm","Neura Robotics","Chips","Humanoide"],"timestamp":"2026-03-09T15:58:11Z"},{"id":"0404-010","title":"Vídeo de Sexta: Robô humanoide aprende tênis jogando contra humanos","summary":"Um robô humanoide foi treinado para jogar tênis recreativo contra oponentes humanos combinando aprendizado por captura de movimento e modelagem biomecânica em tempo real. Após 500 partidas contra jogadores humanos, o robô adaptou seu saque ao estilo único de jogo de cada adversário.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/tennis-playing-robot","video":"https://www.youtube.com/watch?v=fRj34o4hN4I","tags":["Humanoide","Esporte","Aprendizado","Tênis"],"timestamp":"2026-03-21T16:30:04Z"},{"id":"0404-011","title":"Amazon adquire Rivr, fabricante de robô de entrega que sobe escadas","summary":"A Amazon adquiriu a Rivr, startup que fabrica um robô de entrega com rodas capaz de subir escadas de forma autônoma, sinalizando a intenção da gigante do e-commerce de levar entregas até a porta da frente. O acordo é a primeira aquisição da Amazon focada em entrega na soleira da porta.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/amazon-acquires-rivr-maker-of-a-stair-climbing-delivery-robot/","tags":["Amazon","Entrega","Aquisição","Rivr"],"timestamp":"2026-03-19T23:28:37Z"},{"id":"0404-012","title":"Intrinsic, empresa de software robótico do Alphabet, se junta ao Google","summary":"A Intrinsic, empresa de software robótico que se graduou no laboratório X do Alphabet em 2021, passa para o controle direto do Google. A consolidação sinaliza a intenção do Google de integrar as ferramentas de programação robótica da Intrinsic com a pesquisa de IA da DeepMind para uma plataforma robótica ponta a ponta.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/25/alphabet-owned-robotics-software-company-intrinsic-joins-google/","tags":["Google","Intrinsic","Alphabet","Aquisição"],"timestamp":"2026-02-25T20:00:00Z"},{"id":"0404-013","title":"Canopii quer ter sucesso onde fazendas indoor anteriores falharam — com robôs","summary":"As fazendas indoor robóticas e totalmente autônomas da Canopii podem produzir 18 toneladas de ervas e vegetais folhosos por ano em um espaço do tamanho de uma quadra de basquete. Ao contrário de startups anteriores de agricultura indoor, a Canopii usa robôs proprietários para todas as tarefas de cultivo, eliminando os custos de mão de obra que afundaram as concorrentes.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/canopii-looks-to-succeed-where-past-indoor-farms-have-not/","tags":["AgriRobótica","Agricultura Indoor","Startup"],"timestamp":"2026-03-11T14:00:00Z"},{"id":"0404-014","title":"O ponto de inflexão da guerra de drones na Ucrânia — como UAVs autônomos estão mudando os conflitos","summary":"Análise do IEEE Spectrum examina como o conflito na Ucrânia se tornou um campo de provas para a guerra autônoma com drones, com ambos os lados implantando em escala munições de patrulhamento habilitadas por IA e sistemas antidrone. Analistas militares alertam que as lições aprendidas definirão futuros conflitos convencionais.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-drone-warfare","tags":["Drones Militares","Ucrânia","Armas Autônomas"],"timestamp":"2026-03-24T13:00:05Z"},{"id":"0404-015","title":"Anduril mira valuation de 60 bilhões de dólares em nova rodada de captação","summary":"A empresa de tecnologia de defesa Anduril Industries busca uma nova rodada que levaria seu valuation a 60 bilhões de dólares — o dobro de seus 30 bilhões de junho de 2025. Os programas de drones autônomos e veículos submarinos autônomos da Anduril impulsionam rápido crescimento de receita.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/03/anduril-aims-at-60-billion-valuation-in-new-funding-round/","tags":["Anduril","Defesa","Drones","Captação"],"timestamp":"2026-03-03T20:06:45Z"},{"id":"0404-016","title":"Contrato da Gecko Robotics com a Marinha: robôs escaladores de paredes inspecionam toda a frota dos EUA","summary":"Após seu contrato recorde com a Marinha, a Gecko Robotics está implantando robôs escaladores de paredes com adesão magnética para inspecionar integridade do casco, qualidade de solda e corrosão em todas as classes de navios da Marinha dos EUA. Os robôs coletam dados de espessura por ultrassom 10x mais rápido que mergulhadores humanos.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["Gecko Robotics","Marinha","Inspeção","Militar"],"timestamp":"2026-03-17T10:00:00Z"},{"id":"0404-017","title":"O avanço que torna os rostos de robôs menos perturbadores","summary":"Pesquisadores da Columbia Engineering treinaram um robô para produzir movimentos labiais realistas sincronizados à fala usando apenas uma pequena rede neural. Observadores humanos avaliaram a compreensão de fala do robô com pontuações significativamente maiores do que designs anteriores, sugerindo que a sincronização labial é crucial para cruzar o vale da estranheza.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260116035308.htm","tags":["Robôs Sociais","Vale da Estranheza","Columbia","Rosto"],"timestamp":"2026-01-16T10:28:30Z"},{"id":"0404-018","title":"Rover Perseverance da NASA completa primeiro percurso totalmente planejado por IA em Marte","summary":"O Perseverance completou o primeiro percurso em Marte totalmente planejado por IA, onde uma rede neural com visão — rodando no próprio rover — escolheu a rota sem nenhuma entrada dos controladores de missão na Terra. A travessia autônoma de 112 metros abriu uma nova era na exploração planetária.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260131084555.htm","tags":["NASA","Marte","Navegação IA","Autônomo"],"timestamp":"2026-01-31T08:45:55Z"},{"id":"0404-019","title":"Cientistas criam robôs menores que um grão de sal que conseguem pensar","summary":"Pesquisadores de Cornell fabricaram robôs microscópicos — menores que um grão de sal — capazes de perceber o ambiente, tomar decisões e se mover de forma autônoma usando eletrônica alimentada por luz. Os robôs representam as menores máquinas autônomas já criadas, com potencial para aplicações médicas e de materiais.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260105165815.htm","tags":["Microrrobôs","Cornell","Nanotecnologia"],"timestamp":"2026-01-06T07:33:12Z"},{"id":"0404-020","title":"Vídeo de Sexta: Esses robôs nasceram para correr — locomoção modular com pernas","summary":"Uma nova arquitetura de robô modular com pernas permite que os componentes se montem em diferentes configurações e alcancem velocidades de corrida notáveis. O sistema otimiza automaticamente sua marcha para cada configuração montada, tornando-o adaptável a diferentes terrenos e tarefas.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/legged-modular-robot","tags":["Robôs Modulares","Locomoção","Com Pernas"],"timestamp":"2026-03-13T16:00:04Z"},{"id":"0404-021","title":"Vídeo de Sexta: Uma mão robótica com músculos e tendões artificiais","summary":"Esta semana o IEEE Spectrum destaca uma nova mão robótica que substitui servomotores rígidos por músculos artificiais complacentes e cabos tipo tendão. O resultado é uma mão que agarra objetos delicados — de ovos crus a salgadinhos crocantes — sem quebrá-los, usando apenas complacência passiva.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/video-friday-robot-hand-artificial-muscles","video":"https://www.youtube.com/watch?v=LikxFZZO2sk","tags":["Mão Robótica","Músculos Artificiais","Preensão"],"timestamp":"2026-03-06T16:00:05Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-03"] = {"date":"2026-04-03","featured":{"id":"featured-0403","title":"FedEx e Berkshire Gray firmam parceria para implantar robôs classificadores com IA em toda a rede americana","summary":"A FedEx anunciou uma ampla parceria com a Berkshire Gray para implantar robôs de classificação e manipulação alimentados por IA em todas as suas 650 instalações nos EUA ao longo dos próximos três anos. O acordo, estimado em 1,2 bilhão de dólares, é o maior contrato de automação robótica da história da logística.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&h=600&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","Logística","Automação","Berkshire Gray"],"timestamp":"2026-03-31T15:46:50Z"},"articles":[{"id":"0403-001","title":"Robôs de DNA podem administrar remédios e caçar vírus dentro do corpo humano","summary":"Nanobots de DNA programáveis surgem como a próxima fronteira da medicina dirigida. Ao incorporar conceitos de locomoção, detecção e carga útil da robótica em macroescala, pesquisadores criaram máquinas moleculares capazes de navegar pela corrente sanguínea e entregar medicamentos diretamente a células tumorais.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["Nanorobôs","Entrega de medicamentos","DNA","Medicina"],"timestamp":"2026-03-31T07:16:58Z"},{"id":"0403-002","title":"Estrutura de controle permite que robôs flexíveis naveguem em espaços estreitos com menos processamento","summary":"Uma nova estrutura de controle cinemático reduz em 80% o processamento de planejamento de trajetória para robôs macios e contínuos, viabilizando a navegação em tempo real dentro de tubos, dutos e passagens biológicas. O trabalho é um passo importante para o uso de robôs flexíveis em cirurgia e inspeção de infraestrutura.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["Robótica macia","Planejamento de rotas","Cirurgia"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0403-003","title":"Nomadic capta R$ 8,4 milhões para transformar imagens de robôs em dados de treinamento de IA pesquisáveis","summary":"A Nomadic captou 8,4 milhões de dólares para construir uma infraestrutura que converte fluxos brutos de sensores de robôs e veículos autônomos em conjuntos de dados limpos, rotulados e pesquisáveis. O pipeline de aprendizado profundo da empresa processa imagens brutas 50 vezes mais rápido do que equipes de anotação manual.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["Startup","Dados","Treinamento","Veículos autônomos"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0403-004","title":"Sensores robóticos podem dar aos robôs um sentido do toque semelhante ao humano — Pesquisa de Penn State","summary":"Pesquisadores de Penn State desenvolvem sensores de pressão flexíveis capazes de detectar simultaneamente textura, temperatura e força com sensibilidade comparável à das pontas dos dedos humanos. Os sensores utilizam um novo material composto piezoresistivo que permanece funcional após milhares de ciclos de flexão.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-qa-robots-sensors.html","tags":["Sensores táteis","Penn State","Robótica macia"],"timestamp":"2026-03-30T17:00:04Z"},{"id":"0403-005","title":"Transferência de habilidades entre morfologias: robôs com corpos diferentes já podem compartilhar conhecimento","summary":"Pesquisadores de Stanford desenvolveram uma estrutura que permite a robôs com planos corporais fundamentalmente diferentes — braços, pernas, rodas — compartilhar habilidades de manipulação codificando-as como 'vetores de intenção' abstratos, independentes de qualquer forma física particular.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-bodies-skills-intention-based.html","tags":["Aprendizado por transferência","Cross-Embodiment","Stanford"],"timestamp":"2026-03-30T13:20:04Z"},{"id":"0403-006","title":"HEAPGrasp alcança 97,3% de sucesso em objetos desconhecidos em testes de armazém","summary":"O sistema HEAPGrasp combina preensão hierárquica com feedback háptico em tempo real e atinge 97,3% de sucesso em objetos nunca vistos antes, incluindo embalagens altamente deformáveis, produtos escorregadios e peças industriais de formas irregulares.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-heapgrasp-faster-smarter-robots-tricky.html","tags":["Preensão","Logística","Manipulação"],"timestamp":"2026-03-30T11:20:03Z"},{"id":"0403-007","title":"HomeTask-3000: o benchmark de robôs domésticos mais rigoroso até hoje","summary":"Um consórcio de 12 universidades lançou o HomeTask-3000, um benchmark com 3.000 cenários de tarefas domésticas de múltiplas etapas em 47 layouts residenciais realistas. O benchmark expõe lacunas significativas no desempenho atual dos robôs domésticos, especialmente em tarefas que exigem retenção de contexto por vários dias.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-benchmark-robots-chores-real.html","tags":["Benchmark","Robôs domésticos","Pesquisa"],"timestamp":"2026-03-29T11:30:02Z"},{"id":"0403-008","title":"Minúsculos microrrobôs impressos em 3D nadam como animais usando apenas sua forma física","summary":"Microrrobôs impressos em 3D em escala microscópica desenvolvidos na Leiden University navegam e respondem a gradientes ambientais sem sensores, processadores ou baterias, baseando-se exclusivamente na geometria física de seus corpos ao interagir com o fluido ao redor. A abordagem viabiliza classes inteiramente novas de microrrobôs baratos e descartáveis.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["Microrrobôs","Impressão 3D","Locomoção passiva"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0403-009","title":"Gêmeos digitais ajudam robôs de resgate a mapear locais de desastre 10 vezes mais rápido","summary":"Algoritmos de processamento de nuvens de pontos 3D em tempo real permitem agora que robôs de resposta a desastres construam mapas precisos de gêmeos digitais de edifícios desabados em segundos, permitindo planejar rotas seguras para sobreviventes presos muito mais rapidamente do que as abordagens anteriores baseadas em SLAM.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-digital-twins-robots-faster-3d.html","tags":["Resposta a desastres","Mapeamento 3D","SLAM"],"timestamp":"2026-03-26T15:50:01Z"},{"id":"0403-010","title":"O modelo de mundo de difusão de vídeo de Harvard permite que robôs imaginem antes de agir","summary":"Uma nova arquitetura de IA de Harvard utiliza um modelo de difusão de vídeo como 'motor de imaginação' interno, permitindo que robôs simulem mentalmente o resultado de centenas de ações possíveis antes de executar a melhor. A abordagem atinge desempenho humano em 23 dos 30 benchmarks padrão de manipulação.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-video-based-ai-robots-visual.html","tags":["Modelo de mundo","Difusão","Harvard","Planejamento"],"timestamp":"2026-03-26T10:20:03Z"},{"id":"0403-011","title":"Aprendizado por reforço multiagente reduz congestionamentos de robôs em armazéns e aumenta a produtividade em 25%","summary":"Um sistema dinâmico de aprendizado por reforço multiagente implantado em um centro de distribuição simulado da Amazon com 500 robôs aumentou a produtividade de pedidos em 25% ao redirecionar proativamente os robôs ao redor de pontos de congestionamento previstos antes que os bloqueios se formem, em vez de reagir depois que ocorrem.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["Armazém","MARL","Amazon","Produtividade"],"timestamp":"2026-03-26T09:30:01Z"},{"id":"0403-012","title":"Drones inspirados em morcegos navegam em incêndios com visibilidade zero usando ultrassom","summary":"O drone inspirado em morcegos da WPI navega em ambientes com fumaça densa e visibilidade zero usando um sistema de ecolocalização por ultrassom e uma IA personalizada que interpreta os sinais refletidos como um mapa 3D. Corpos de bombeiros estão pilotando o sistema para reconhecimento de primeiros socorristas.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ultrasound-palm-sized-drones-fog.html","tags":["Drones","Combate a incêndios","Ultrassom","Navegação"],"timestamp":"2026-03-26T09:06:49Z"},{"id":"0403-013","title":"Mão robótica de liga com memória de forma sem motor é 70% mais leve que designs com servos","summary":"Ao substituir servomotores elétricos por fios de liga com memória de forma e uma transmissão mecânica engenhosa, pesquisadores construíram uma mão robótica de cinco dedos que pesa apenas 180 gramas — 70% mais leve que designs comparáveis com servos — mantendo velocidades de atuação abaixo de 100 ms.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["Mão robótica","SMA","Leveza","Próteses"],"timestamp":"2026-03-25T10:00:04Z"},{"id":"0403-014","title":"Mão protética controlada por pulseira dá aos amputados controle individual de cada dedo","summary":"Uma pulseira EMG do MIT lê sinais musculares para fornecer controle em tempo real de cada dedo de uma mão protética. Os usuários obtêm controle independente e confiável dos dedos em menos de 20 horas de treinamento, em comparação com mais de 200 horas exigidas por próteses mioeléctricas convencionais.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["Próteses","EMG","MIT","Acessibilidade"],"timestamp":"2026-03-25T06:00:09Z"},{"id":"0403-015","title":"Robô colhedor de tomates aprende a colher por dificuldade e melhora o rendimento em 35%","summary":"Em vez de colher tomates na ordem em que os encontra, um novo robô agrícola prevê a dificuldade de colheita com base na posição do fruto, na oclusão e na orientação do caule, priorizando os alvos mais fáceis. A estratégia melhorou o rendimento total da colheita em 35% em ensaios controlados em estufa.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["AgriRobotics","Tomate","Planejamento com IA"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0403-016","title":"Drone BRINC Guardian: respondedor policial de emergência que carrega Narcan e persegue carros","summary":"A BRINC revelou o Guardian, um drone policial projetado para resposta rápida ao 911. Ele integra conectividade Starlink para cobertura nacional, pode distribuir Narcan em chamadas de overdose e persegue suspeitos a 96 km/h. Defensores das liberdades civis levantaram preocupações significativas sobre o sistema.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"Ars Technica","url":"https://arstechnica.com/gadgets/2026/03/brincs-new-police-drone-uses-starlink-carries-narcan-chases-vehicles-at-60mph/","tags":["Polícia","Drone","BRINC","Emergência"],"timestamp":"2026-03-25T21:12:03Z"},{"id":"0403-017","title":"Austrália implanta robôs para inspecionar fazendas solares no calor extremo do interior","summary":"Robôs de inspeção movidos a IA estão substituindo o perigoso trabalho humano de manutenção nas maiores fazendas solares da Austrália, percorrendo quilômetros de terreno desértico acidentado a 50 °C para limpar painéis, medir eficiência e detectar falhas com câmeras termográficas.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["Solar","Austrália","Inspeção","Industrial"],"timestamp":"2026-03-25T18:10:07Z"},{"id":"0403-018","title":"Drones de busca e resgate com IA localizam desaparecidos 4 vezes mais rápido que equipes terrestres","summary":"Uma plataforma de drones multissensor integrando câmeras térmicas, infravermelhas e visuais com um sistema de detecção por IA encontrou pessoas desaparecidas em áreas silvestres quatro vezes mais rápido do que equipes de busca terrestres sozinhas. A tecnologia está sendo adotada por organizações de resgate em montanha na Suíça e no Colorado.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-drones-paired-ai-searchandrescue-teams.html","tags":["SAR","Drones","Térmico","Emergência"],"timestamp":"2026-03-24T14:20:05Z"},{"id":"0403-019","title":"Amazon adquire Fauna Robotics: humanoide Sprout projetado para lares e hospitais","summary":"A aquisição da Fauna Robotics pela Amazon incorpora à família Amazon o Sprout da empresa — um humanoide do tamanho de uma criança com foco social. O Sprout foi projetado para funcionar em ambientes não estruturados como salas de estar e corredores de hospital, complementando a frota de robôs de armazém existente da Amazon.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-amazon-buys-fauna-robotics-maker.html","tags":["Amazon","Humanoide","Robôs domésticos","Saúde"],"timestamp":"2026-03-25T05:30:01Z"},{"id":"0403-020","title":"O enxame sem eletrônica de Georgia Tech: robôs mecânicos que se auto-organizam","summary":"Pesquisadores de Georgia Tech demonstraram um enxame de robôs puramente mecânicos — sem sensores, processadores nem baterias — que alcançam comportamento coletivo auto-organizado por meio de interações físicas de forma. O trabalho desafia suposições fundamentais sobre o que é necessário para a inteligência de enxame.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["Enxame","Georgia Tech","Mecânico","Auto-organização"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0403-021","title":"Robôs ROS controlados por LLM respondem a comandos em inglês comum em tempo real","summary":"Uma nova camada de middleware integra modelos de linguagem de nível GPT-4 ao Robot Operating System, permitindo que engenheiros e não especialistas comandem comportamentos robóticos complexos de múltiplas etapas usando linguagem natural. O sistema foi validado em cinco plataformas robóticas diferentes.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-combining-robot-llms-natural-language.html","tags":["LLM","ROS","Linguagem natural","Controle"],"timestamp":"2026-04-01T08:10:01Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-02"] = {"date":"2026-04-02","featured":{"id":"featured-0402","title":"O modelo fundacional π0 da Physical Intelligence: o cérebro robótico de propósito geral mais capaz até hoje","summary":"O modelo fundacional π0 da Physical Intelligence, que pode controlar diversos tipos de robôs sem ajuste fino específico para tarefas, estaria sendo licenciado por seis grandes fabricantes OEM de robótica enquanto a empresa prepara uma captação de US$ 1 bilhão. Resultados iniciais mostram que o modelo se generaliza para novas tarefas com menos de 100 demonstrações.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=1200&h=600&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","Modelo Fundacional","Financiamento"],"timestamp":"2026-03-27T23:59:40Z"},"articles":[{"id":"0402-001","title":"Amazon acaba de comprar a Fauna Robotics, criadora do humanoide de tamanho infantil Sprout","summary":"A segunda aquisição robótica da Amazon em um mês incorpora a Fauna Robotics e seu humanoide Sprout. O Sprout é projetado para ser um companheiro social em lares e hospitais, operando com segurança perto de crianças e idosos graças ao seu avançado sistema de desvio de colisões e comunicação expressiva.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/amazon-just-bought-a-startup-making-kid-size-humanoid-robots/","tags":["Amazon","Fauna Robotics","Aquisição","Humanoide"],"timestamp":"2026-03-25T00:53:39Z"},{"id":"0402-002","title":"Agile Robots faz parceria com Google DeepMind: dados para modelos fundacionais, modelos para hardware","summary":"Em uma parceria mutuamente benéfica, a Agile Robots coletará milhões de pontos de dados de demonstração de tarefas usando suas plataformas humanoides e os compartilhará com o Google DeepMind. Em troca, os modelos fundacionais de robótica da DeepMind serão integrados à plataforma robótica de próxima geração da Agile.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/agile-robots-becomes-the-latest-robotics-company-to-partner-with-google-deepmind/","tags":["Agile Robots","Google DeepMind","Parceria"],"timestamp":"2026-03-24T12:05:00Z"},{"id":"0402-003","title":"A guerra de drones autônomos na Ucrânia está mudando a cara dos conflitos militares","summary":"Ambos os lados no conflito ucraniano estão implantando milhares de drones autônomos habilitados com IA semanalmente. O ritmo da evolução tecnológica ultrapassou o direito internacional, com especialistas alertando que o controle humano significativo está sendo corroído à medida que os alcances de combate autônomo diminuem para segundos.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-drone-warfare","tags":["Militar","Drones","Ucrânia","Ética da IA"],"timestamp":"2026-03-24T13:00:05Z"},{"id":"0402-004","title":"Drone de busca e resgate com IA térmica encontra caminhantes desaparecidos 4x mais rápido","summary":"Em parceria com equipes suíças de resgate em montanha, um novo drone multissensor que combina câmeras térmicas, infravermelhas e coloridas com um mecanismo de detecção por IA localizou caminhantes desaparecidos quatro vezes mais rápido do que as buscas terrestres tradicionais em condições alpinas simuladas.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-drones-paired-ai-searchandrescue-teams.html","tags":["Busca e Resgate","Drones","Resgate em Montanha","Térmica"],"timestamp":"2026-03-24T14:20:05Z"},{"id":"0402-005","title":"Níveis de capacidade humanoide da Fraunhofer: um novo padrão para avaliar a autonomia robótica","summary":"O instituto Fraunhofer HNFIZ publicou um sistema de classificação de cinco níveis para as capacidades dos robôs humanoides, cobrindo mobilidade, manipulação e autonomia cognitiva. O framework fornece a fabricantes, reguladores e clientes uma linguagem comum para comparar sistemas humanoides.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["Humanoide","Padrões","Fraunhofer","Autonomia"],"timestamp":"2026-03-23T17:20:07Z"},{"id":"0402-006","title":"Robô-pássaro da Rutgers usa asas flexíveis para superar drones em eficiência energética","summary":"O ornitóptero da Rutgers alcança eficiência energética 3 vezes maior do que drones quadricópteros equivalentes em velocidades abaixo de 5 m/s, usando asas articuladas que se adaptam ao vento em tempo real. As propriedades aerodinâmicas únicas do design o tornam particularmente eficaz para monitoramento de fauna em florestas densas.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["Ornitóptero","Rutgers","Bio-Inspirado","Eficiência Energética"],"timestamp":"2026-03-23T13:20:02Z"},{"id":"0402-007","title":"Robô rastreador de odores localiza vazamentos de gás e explosivos com um sensor danificado","summary":"Um robô olfativo bio-inspirado projetado para detecção de vazamentos de gás e localização de explosivos mantém operação confiável mesmo quando uma de suas duas matrizes de sensores falha. O design tolerante a falhas é inspirado em como insetos continuam rastreando odores após perder uma antena.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-insect-robot-tracks-odors-antenna.html","tags":["Olfativo","Segurança","Detecção de Gás","Tolerância a Falhas"],"timestamp":"2026-03-23T12:00:03Z"},{"id":"0402-008","title":"Robôs tutores em escolas de Chicago ensinam empatia sem fingir ser humanos","summary":"Um experimento em 12 escolas primárias de Chicago usa robôs de assistência social para ensinar habilidades de aprendizado socioemocional. Crucialmente, os robôs são transparentes sobre serem máquinas, e a pesquisa mostra que essa honestidade melhora os resultados de aprendizagem em comparação com tutores robóticos antropomórficos.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-chicago-robot-sel-effectively-human.html","tags":["Educação","Aprendizado Socioemocional","Robôs Sociais","Ética"],"timestamp":"2026-03-20T06:10:01Z"},{"id":"0402-009","title":"WANDER-Bot: um robô eólico para monitoramento perpétuo de ambientes extremos","summary":"O WANDER-bot da Cranfield University aproveita a energia eólica para alimentar sua locomoção e sensores, permitindo operação autônoma indefinida em desertos, tundras e terrenos vulcânicos. O design impresso em 3D, de US$ 200, poderia viabilizar redes de monitoramento ambiental em escala continental.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-powered-robot-enable-term-exploration.html","tags":["Energia Eólica","Meio Ambiente","Exploração","Cranfield"],"timestamp":"2026-03-19T16:20:03Z"},{"id":"0402-010","title":"Robôs que aprendem mais rápido que seus professores humanos — novo avanço em aprendizado por imitação","summary":"Um novo framework de 'aprendizado por imitação acelerado' identifica ineficiências nas demonstrações humanas e as otimiza, permitindo que os robôs executem tarefas aprendidas até 30% mais rápido do que o humano que demonstrou, após apenas 10 ensaios de prática.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-smarter-faster-human-ai-robots.html","tags":["Aprendizado por Imitação","Aprendizado Robótico","Eficiência"],"timestamp":"2026-03-19T14:20:06Z"},{"id":"0402-011","title":"Gecko Robotics vence maior contrato de robótica da Marinha dos EUA para inspecionar toda a frota","summary":"A Marinha concedeu à Gecko Robotics um contrato de cinco anos para implantar robôs de inspeção escaladores de paredes em cada classe de embarcação. Os robôs usam sensores de ultrassom, infravermelho e visual para monitorar continuamente a integridade do casco, a qualidade das soldas e a corrosão, criando modelos de manutenção preditiva.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["Marinha","Inspeção","Militar","Gecko Robotics"],"timestamp":"2026-03-17T10:00:00Z"},{"id":"0402-012","title":"Colapso do robô no restaurante Haidilao viraliza: AgiBot dança descontroladamente","summary":"Um vídeo de um garçom humanoide AgiBot perdendo o controle e dançando de forma errática em um restaurante de hot pot Haidilao em Cupertino acumulou mais de 40 milhões de visualizações. A empresa atribuiu a falha a um caso extremo de atualização de software e desde então implantou um patch em todo o sistema.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/restaurant-dancing-robot-went-wild-hot-pot-cupertino-haidilao-agibot/","tags":["AgiBot","Restaurante","Viral","Falha"],"timestamp":"2026-03-19T21:13:50Z"},{"id":"0402-013","title":"RJ Scaringe da Rivian: parem de construir robôs humanoides e construam máquinas de propósito específico","summary":"O CEO da Rivian e fundador da Mind Robotics, RJ Scaringe, argumenta que a indústria robótica comete um erro fundamental ao perseguir robôs com forma humana para tarefas de fábrica. Sua nova empresa projeta especificamente robôs adaptados às suas tarefas pretendidas, não à anatomia humana.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/15/rivians-rj-scaringe-thinks-were-doing-robots-all-wrong/","tags":["Mind Robotics","Rivian","Industrial","Opinião"],"timestamp":"2026-03-15T14:30:00Z"},{"id":"0402-014","title":"Mind Robotics capta R$ 500 milhões para robôs de fábrica treinados na própria linha de produção da Rivian","summary":"A Mind Robotics, spin-off da Rivian, captou US$ 500 milhões para construir e implantar robôs industriais com IA treinados diretamente na Gigafábrica da Rivian. A startup tem acesso exclusivo a terabytes de dados de demonstração de fábrica, uma vantagem competitiva significativa.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/rivian-mind-robotics-series-a-500m-fund-raise-industrial-ai-powered-robots/","tags":["Rivian","Startup","Industrial","Financiamento"],"timestamp":"2026-03-11T16:12:02Z"},{"id":"0402-015","title":"Chips Qualcomm IQ10 alimentam o cérebro humanoide de próxima geração da Neura Robotics","summary":"A Neura Robotics está construindo sua nova plataforma humanoide em torno do processador AI IQ10 da Qualcomm, que fornece 40 TOPS de potência de inferência no dispositivo com menos de 20 watts. A parceria desafia a dominância da Nvidia no mercado de plataformas computacionais para robótica.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/09/qualcomms-partnership-with-neura-robotics-is-just-the-beginning/","tags":["Qualcomm","Neura Robotics","Chips","Hardware"],"timestamp":"2026-03-09T15:58:11Z"},{"id":"0402-016","title":"Fazenda robótica autônoma da Canopii produz 18 toneladas de ervas por ano no espaço de uma quadra de basquete","summary":"A Canopii usa uma pilha verticalmente integrada de robôs personalizados — semeadura, irrigação, monitoramento e colheita — para operar uma fazenda interna totalmente autônoma. Ao contrário de players anteriores que falharam nos custos de mão de obra, a abordagem totalmente robótica da Canopii alcança rentabilidade pela metade do preço das fazendas internas tradicionais.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/canopii-looks-to-succeed-where-past-indoor-farms-have-not/","tags":["AgriRobótica","Agricultura Indoor","Autônomo"],"timestamp":"2026-03-11T14:00:00Z"},{"id":"0402-017","title":"Intrinsic se une ao Google: Alphabet consolida sua plataforma de software robótico","summary":"Após cinco anos como empresa independente da Alphabet, a empresa de software robótico Intrinsic é absorvida pelo Google. O movimento consolida os ativos robóticos da Alphabet sob um mesmo teto e sinaliza a intenção do Google de construir uma plataforma robótica unificada combinando software, modelos de IA e parcerias de hardware.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/25/alphabet-owned-robotics-software-company-intrinsic-joins-google/","tags":["Google","Intrinsic","Alphabet","Software"],"timestamp":"2026-02-25T20:00:00Z"},{"id":"0402-018","title":"A indústria chinesa de robôs humanoides está superando o Ocidente em implantações comerciais","summary":"Uma análise detalhada do TechCrunch constata que os fabricantes chineses de humanoides enviaram mais unidades comercialmente nos últimos 12 meses do que todas as empresas ocidentais combinadas, impulsionados por custos de fabricação mais baixos, ciclos de iteração mais rápidos e agressivos subsídios governamentais.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/28/why-chinas-humanoid-robot-industry-is-winning-the-early-market/","tags":["China","Humanoide","Mercado","Competição"],"timestamp":"2026-02-28T15:00:00Z"},{"id":"0402-019","title":"Valuation de US$ 60 bilhões da Anduril: startup de robôs de defesa cresce mais rápido do que qualquer empresa de armamentos na história","summary":"A Anduril Industries está mirando um valuation de US$ 60 bilhões em sua próxima rodada de financiamento, o que a tornaria a empresa de tecnologia de defesa mais valiosa da história pela velocidade de crescimento do valuation. A receita de enxames de drones autônomos, veículos submarinos e sistemas de vigilância com IA triplicou em 18 meses.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/03/anduril-aims-at-60-billion-valuation-in-new-funding-round/","tags":["Anduril","Defesa","Financiamento","Drones"],"timestamp":"2026-03-03T20:06:45Z"},{"id":"0402-020","title":"30 anos de robôs bípedes: como o Honda P2 mudou tudo","summary":"O IEEE designou o Honda P2 — o primeiro robô bípede verdadeiramente autônomo — como marco oficial do IEEE, 30 anos após sua apresentação. O algoritmo de caminhada dinâmica do P2, desenvolvido pelo engenheiro Masato Hirose, é o ancestral direto de quase todos os robôs bípedes desenvolvidos desde então.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/honda-p2-robot-ieee-milestone","tags":["Honda","História","Bípede","IEEE"],"timestamp":"2026-03-25T18:00:05Z"},{"id":"0402-021","title":"Aquisição da Rivr pela Amazon: robô sobe escadas e aproxima a entrega na porta do destino","summary":"A aquisição pela Amazon da Rivr, fabricante de um robô com rodas capaz de subir escadas de forma autônoma e navegar pelos halls de edifícios, marca o primeiro investimento sério da empresa na entrega do último trecho. A tecnologia poderia eventualmente permitir a entrega de encomendas em qualquer andar de qualquer edifício.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/amazon-acquires-rivr-maker-of-a-stair-climbing-delivery-robot/","tags":["Amazon","Entrega","Aquisição","Última Milha"],"timestamp":"2026-03-19T23:28:37Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-04-01"] = {"date":"2026-04-01","featured":{"id":"featured-0401","title":"Amazon adquire duas startups de robótica em um mês: Rivr e Fauna Robotics","summary":"A Amazon concluiu as aquisições da Rivr (robô de entrega que sobe escadas) e da Fauna Robotics (humanoide social de tamanho infantil Sprout) no mesmo mês, sinalizando uma expansão agressiva da automação puramente de depósito para lares e entrega de última milha. Analistas estimam o valor combinado das transações em mais de 400 milhões de dólares.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&h=600&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/amazon-just-bought-a-startup-making-kid-size-humanoid-robots/","tags":["Amazon","Aquisição","Estratégia","Humanoide"],"timestamp":"2026-03-25T00:53:39Z"},"articles":[{"id":"0401-001","title":"Pesquisadores criam enxame robótico sem eletrônica, sem baterias e sem cérebro","summary":"O novo enxame puramente mecânico da Georgia Tech alcança comportamento coletivo emergente apenas a partir de interações de forma física. A pesquisa desafia premissas fundamentais sobre inteligência de enxame e abre caminho para coletivos robóticos ultra-baratos e implantáveis em massa para monitoramento ambiental.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["Enxame","Georgia Tech","Mecânico","Emergente"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0401-002","title":"LLM + ROS: controle de robôs por linguagem natural já é realidade para operadores não especialistas","summary":"Uma nova ponte middleware de ROS para grandes modelos de linguagem permite que qualquer pessoa comande robôs industriais em linguagem simples, sem necessidade de programação. O sistema interpreta instruções ambíguas, faz perguntas de esclarecimento e gera sequências de ações seguras em tempo real.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-combining-robot-llms-natural-language.html","tags":["LLM","ROS","Linguagem Natural","Humano-Robô"],"timestamp":"2026-04-01T08:10:01Z"},{"id":"0401-003","title":"Novo framework de controle robótico flexível reduz em 80% os cálculos de planejamento de trajetória para inspeção de dutos","summary":"Um novo framework de controle cinemático para robôs macios e contínuos reduz o processamento em 80%, possibilitando navegação em tempo real dentro de dutos estreitos, vasos sanguíneos e cavidades irregulares. A abordagem foi validada em protótipos de robôs de endoscopia e sistemas de inspeção de gasodutos.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["Robótica Macia","Dutos","Controle","Médico"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0401-004","title":"Nanorobôs de DNA: máquinas moleculares que caçam vírus e entregam medicamentos contra o câncer","summary":"Equipes de engenharia do MIT e do Caltech estão desenvolvendo nanobots de DNA programáveis capazes de identificar tipos celulares específicos, se ligar a eles e liberar cargas terapêuticas com precisão subcelular. Ensaios em animais mostram eficiência de entrega de medicamentos 10 vezes maior em comparação com abordagens de nanopartículas.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["Nanorobôs","Médico","Câncer","Entrega de Medicamentos"],"timestamp":"2026-03-31T07:16:58Z"},{"id":"0401-005","title":"FedEx aposta alto em robôs parceiros: acordo com a Berkshire Gray cobre todas as 650 instalações nos EUA","summary":"Em vez de construir sua própria divisão de robótica, a FedEx assinou com a Berkshire Gray para fornecer robôs de triagem, separação e manuseio de pacotes impulsionados por AI a todas as suas instalações americanas. A parceria plurianual deve eliminar 12.000 funções manuais repetitivas e reduzir erros de triagem em 95%.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","Logística","Berkshire Gray","Automação"],"timestamp":"2026-03-31T15:46:50Z"},{"id":"0401-006","title":"Nomadic transforma vídeos de veículos autônomos e robôs em conjuntos de dados de treinamento limpos e capta R$ 8,4 milhões","summary":"Com 8,4 milhões de dólares em novo financiamento, a Nomadic está construindo a camada de infraestrutura de dados para a era do AI físico: convertendo filmagens brutas de robôs e veículos autônomos em conjuntos de dados limpos, rotulados e consultáveis que as equipes podem usar para treinar e avaliar modelos sem anotação manual.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["Startup","Dados","Treinamento","AI Físico"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0401-007","title":"Physical Intelligence estaria em negociações para captação de US$ 1 bilhão e dobrar sua avaliação","summary":"π (Physical Intelligence) está em conversas com Thrive Capital, Founders Fund e Lachy Groom para uma rodada de 1 bilhão de dólares que levaria sua avaliação a 11,2 bilhões em menos de um ano. A rodada financiaria a comercialização do modelo π0 junto aos fabricantes de robôs parceiros.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","Financiamento","Modelo de Fundação"],"timestamp":"2026-03-27T23:59:40Z"},{"id":"0401-008","title":"Vídeo da sexta: robô bípede Roadrunner atinge 5 m/s com sistema híbrido roda-perna","summary":"Roadrunner é um robô bípede com rodas retráteis nos pés, permitindo alternar entre caminhada e rolagem dependendo do terreno. Em ambientes planos alcança 5 m/s — entre os robôs com pernas mais rápidos já demonstrados — mantendo plena capacidade de subir escadas.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/roadrunner-bipedal-robot","video":"https://www.youtube.com/watch?v=tF4DML7FIWk","tags":["Bípede","Velocidade","Com Rodas","Locomoção"],"timestamp":"2026-03-27T16:30:03Z"},{"id":"0401-009","title":"Pequenos robôs impressos em 3D navegam sem sensores nem software — pura física","summary":"A Universidade de Leiden demonstrou robôs microscópicos impressos em 3D que realizam natação direcional e navegação usando apenas as propriedades físicas de sua forma e material — zero eletrônica, zero código. O trabalho pode viabilizar bilhões de robôs sensores ambientais baratos e descartáveis.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["Microrrobôs","Impressão 3D","Passivo","Leiden"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0401-010","title":"Robôs de desastre obtêm mapas mais rápidos: avanço no processamento de nuvem de pontos 3D em tempo real","summary":"Novos algoritmos baseados em convoluções de tensores esparsos e correspondência de características aprendidas permitem que robôs de resgate construam mapas 3D precisos de ambientes de desastre 10 vezes mais rápido do que as abordagens SLAM anteriores. O sistema opera em tempo real em hardware de borda já disponível nas plataformas robóticas comerciais.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-digital-twins-robots-faster-3d.html","tags":["SLAM","Mapeamento 3D","Desastre","Computação de Borda"],"timestamp":"2026-03-26T15:50:01Z"},{"id":"0401-011","title":"AI de imaginação da Harvard: robôs planejam gerando vídeos do próprio futuro","summary":"O novo modelo de mundo por difusão de vídeo da Harvard permite que robôs planejem tarefas de múltiplas etapas gerando um vídeo mental de cada sequência de ações possível. O robô escolhe o plano cujo resultado imaginado melhor corresponde ao seu objetivo, alcançando desempenho de ponta em 23 benchmarks de manipulação.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-video-based-ai-robots-visual.html","tags":["Modelo de Mundo","Planejamento","Harvard","Difusão"],"timestamp":"2026-03-26T10:20:03Z"},{"id":"0401-012","title":"Solução para congestionamento de robôs em depósito aumenta a produtividade da Amazon em 25% na simulação","summary":"Um controlador de aprendizado por reforço multi-agente (MARL) treinado em uma simulação de alta fidelidade de depósito da Amazon aprendeu a prevenir proativamente o congestionamento de robôs prevendo gargalos de tráfego com 30 segundos de antecedência. A Amazon planeja iniciar projetos-piloto no mundo real no terceiro trimestre de 2026.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["Depósito","Amazon","MARL","Eficiência"],"timestamp":"2026-03-26T09:30:01Z"},{"id":"0401-013","title":"Lucid Bots capta US$ 20 milhões: demanda por drones de limpeza de janelas e lavagem a pressão explode","summary":"Proprietários de edifícios comerciais estão adotando rapidamente os drones de limpeza da Lucid Bots, pois os custos de mão de obra e as regulamentações de segurança tornam a limpeza manual em altura cada vez mais inviável. A Série B de 20 milhões de dólares financiará a expansão da fabricação e o desenvolvimento de um novo drone de reparação de fachadas.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/lucid-bots-raises-20m-to-keep-up-with-demand-for-its-window-washing-drones/","tags":["Drones","Limpeza","Comercial","Financiamento"],"timestamp":"2026-03-25T11:00:00Z"},{"id":"0401-014","title":"Robôs pneumáticos levantam 100 vezes seu peso: a descoberta pneumática da Arizona State University","summary":"Os novos supermúsculos pneumáticos da Arizona State University usam ar comprimido e geometria bio-inspirada para alcançar relações força-peso 100 vezes superiores ao músculo humano. Os atuadores sobrevivem à água fervente, ao ácido e a abrasivos, tornando-os candidatos para ambientes industriais e espaciais extremos.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-air-powered-artificial-muscles-robots.html","tags":["Atuador","Pneumático","Arizona State","Força"],"timestamp":"2026-04-02T11:20:06Z"},{"id":"0401-015","title":"Robô colhedor de tomate aprende a priorizar as colheitas fáceis e aumenta o rendimento em 35%","summary":"Um algoritmo de colheita sensível à dificuldade transforma o desempenho de robôs agrícolas ao prever quais frutas serão mais fáceis de colher antes de comprometer-se com uma abordagem. A técnica se generaliza além dos tomates e foi testada com sucesso em morangos e pimentões.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["AgriRobótica","Colheita","Planejamento","Alimentos"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0401-016","title":"Acordo da Gecko Robotics com a Marinha: robôs escaladores inspecionarão todos os navios de guerra americanos","summary":"Os robôs escaladores de paredes com aderência magnética da Gecko Robotics inspecionarão o casco e a integridade estrutural de cada classe de navio da Marinha dos EUA sob um novo contrato de cinco anos. Os robôs coletam leituras de espessura por ultrassom 10 vezes mais rápido que mergulhadores humanos, possibilitando manutenção preditiva em vez de reativa.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["Marinha","Militar","Inspeção","Robô Escalador"],"timestamp":"2026-03-17T10:00:00Z"},{"id":"0401-017","title":"O padrão humanoide de 5 níveis da Fraunhofer: os níveis SAE para autonomia robótica","summary":"O Fraunhofer HNFIZ alemão publicou a primeira classificação de capacidades padronizada em cinco níveis para robôs humanoides, cobrindo mobilidade, manipulação e autonomia cognitiva. O nível 5 — autonomia cognitiva total — atualmente não tem nenhum robô comercial, fornecendo à indústria um alvo claro de roteiro.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["Humanoide","Padrões","Autonomia","Fraunhofer"],"timestamp":"2026-03-23T17:20:07Z"},{"id":"0401-018","title":"Modelo de marcha por rede neural replica o movimento de cavalos, cães e gatos para melhorar robôs quadrúpedes","summary":"Uma rede neural bio-inspirada que modela com precisão a locomoção de animais quadrúpedes em marchas de caminhada, trote e galope está sendo usada para melhorar a qualidade de movimento de robôs com pernas. O modelo também lida com transições automáticas de marcha, um desafio persistente no controle de robôs com pernas.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-artificial-neural-network-gait-patterns.html","tags":["Quadrúpede","Locomoção","Bio-Inspirado","Marcha"],"timestamp":"2026-03-23T17:20:08Z"},{"id":"0401-019","title":"Robô rastreador de odores inspirado em insetos funciona mesmo com sensores danificados","summary":"Um robô rastreador de odores tolerante a falhas inspirado na olfação de insetos consegue localizar vazamentos de gás e explosivos de forma confiável mesmo operando com um de seus dois conjuntos de sensores desativado. Testes de campo em ambientes industriais mostram precisão consistente em condições reais.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-insect-robot-tracks-odors-antenna.html","tags":["Olfação","Detecção de Gás","Tolerância a Falhas","Bio-Inspirado"],"timestamp":"2026-03-23T12:00:03Z"},{"id":"0401-020","title":"Lições dos drones militares da Ucrânia estão reformulando os padrões de segurança de carros autônomos","summary":"Análise da IEEE Spectrum mostra como as técnicas de navegação por AI adversarial desenvolvidas na guerra de drones da Ucrânia — resistência a spoofing, navegação resiliente a jamming, avaliação autônoma de ameaças — estão sendo adaptadas para sistemas civis de direção autônoma para lidar com negação de GPS e ataques a sensores.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/military-drones-self-driving-cars","tags":["Militar","Direção Autônoma","Segurança","Navegação"],"timestamp":"2026-03-02T12:00:02Z"},{"id":"0401-021","title":"Drone ornitóptero com forma de pássaro é 3 vezes mais eficiente que um quadrirotor em baixa velocidade","summary":"O robô ornitóptero de asas batentes da Rutgers University alcança três vezes a eficiência energética de um quadrirotor em velocidades abaixo de 5 m/s, tornando-o ideal para missões de monitoramento de vida selvagem de longa duração. O design da asa é inspirado na anatomia do falcão peregrino e otimizado por meio de 10.000 horas de simulação CFD.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["Ornitóptero","Bio-Inspirado","Eficiência","Vida Selvagem"],"timestamp":"2026-03-23T13:20:02Z"}]};

window.__NEWS_DATA_LOCALES__["pt-BR"]["2026-03-31"] = {"date":"2026-03-31","featured":{"id":"featured-0331","title":"Robôs de DNA podem entregar medicamentos e caçar vírus dentro do seu corpo — Estudo na Nature","summary":"Um estudo histórico publicado na Nature demonstra nanorobôs baseados em DNA que navegam pela corrente sanguínea, identificam células cancerígenas pela assinatura de proteínas de superfície, se acoplam a elas e liberam uma carga de quimioterapia com precisão subcelular. A tecnologia alcançou regressão tumoral completa em 80% dos modelos murinos sem qualquer toxicidade fora do alvo.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=1200&h=600&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["Nanorobôs","Câncer","Entrega de Medicamentos","DNA"],"timestamp":"2026-03-31T07:16:58Z"},"articles":[{"id":"0331-001","title":"FedEx firma parceria com Berkshire Gray em acordo de automação robótica de 1,2 bilhão de dólares","summary":"A FedEx optou por uma estratégia baseada em parcerias, contratando a Berkshire Gray para instalar robôs de triagem e de pacotes movidos por AI em suas 650 instalações nos EUA. A decisão vem após a FedEx ter passado três anos avaliando se deveria desenvolver sua própria capacidade robótica internamente.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","Logística","Berkshire Gray","Automação"],"timestamp":"2026-03-31T15:46:50Z"},{"id":"0331-002","title":"Nomadic fecha rodada de 8,4 milhões de dólares para construir a camada de infraestrutura de dados para AI física","summary":"A Nomadic converte fluxos brutos de câmeras de robôs e veículos autônomos em conjuntos de dados limpos, estruturados e pesquisáveis usando deep learning. Com 8,4 milhões em financiamento Série A, a empresa expande sua capacidade de processamento e adiciona suporte para sensores LiDAR e radar.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["Startup","Dados","AI Física","Financiamento"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0331-003","title":"Navegação flexível de robôs em espaços apertados: 80% menos de computação com novo framework","summary":"Um novo framework de planejamento de trajetória para robôs macios e contínuos reduz o processamento necessário em 80% mantendo a precisão de navegação em passagens estreitas. O avanço permite o controle em tempo real de robôs macios em microprocessadores comuns sem aceleração GPU.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["Robótica Macia","Controle","Computação","Médico"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0331-004","title":"Physical Intelligence mira avaliação de 11,2 bilhões com nova captação de 1 bilhão de dólares","summary":"A Physical Intelligence (π) está em negociações avançadas com VCs de primeiro nível para uma rodada que elevaria sua avaliação a 11,2 bilhões de dólares em menos de um ano de operação. O modelo π0 da empresa — o cérebro robótico de propósito geral mais capaz disponível — já está licenciado por seis fabricantes de hardware OEM.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","π0","Financiamento","Modelo Fundacional"],"timestamp":"2026-03-27T23:59:40Z"},{"id":"0331-005","title":"Video Friday: Roadrunner — o robô bípede que combina rodas e caminhada","summary":"O Video Friday do IEEE Spectrum destaca o Roadrunner, um robô bípede com rodas retráteis nos pés para deslocamento rápido em terreno plano combinado com marcha bípede tradicional para escadas e terrenos acidentados. O design híbrido representa uma nova direção importante na locomoção humanoide.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/roadrunner-bipedal-robot","video":"https://www.youtube.com/watch?v=tF4DML7FIWk","tags":["Bípede","Rodas","Híbrido","Locomoção"],"timestamp":"2026-03-27T16:30:03Z"},{"id":"0331-006","title":"Microrrobôs puramente físicos navegam como animais — zero eletrônica","summary":"Os microrrobôs impressos em 3D da Universidade de Leiden navegam gradientes químicos e correntes usando apenas a física passiva de sua geometria impressa. Sem eletrônica ou lógica de controle, os robôs custam menos de um centavo cada e podem ser fabricados aos milhões para enxames de monitoramento ambiental.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["Microrrobôs","Leiden","Passivo","Enxame"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0331-007","title":"Drone BRINC Guardian acende debate sobre liberdades civis: Narcan + Starlink + perseguição a 96 km/h","summary":"O drone policial Guardian da BRINC integra Starlink, distribuição de Narcan e capacidade de perseguição a 96 km/h, tornando-o o drone de segurança pública mais capaz já oferecido comercialmente. Organizações de privacidade e liberdades civis pediram audiências no Congresso sobre drones policiais autônomos.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"Ars Technica","url":"https://arstechnica.com/gadgets/2026/03/brincs-new-police-drone-uses-starlink-carries-narcan-chases-vehicles-at-60mph/","tags":["Drone Policial","Liberdades Civis","BRINC","Ética"],"timestamp":"2026-03-25T21:12:03Z"},{"id":"0331-008","title":"Frota australiana de robôs solares percorre 13.000 km de deserto por ano sob 50 °C","summary":"Uma frota de robôs de inspeção movidos por AI é agora responsável pela manutenção das maiores fazendas solares da Austrália em 13.000 km de terreno do interior. Operando em temperaturas que hospitalizariam trabalhadores humanos, os robôs aumentam a detecção de falhas em 400% enquanto reduzem os custos de manutenção em 70%.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["Solar","Austrália","Industrial","Inspeção"],"timestamp":"2026-03-25T18:10:07Z"},{"id":"0331-009","title":"Visão de Melania Trump de robô como professor doméstico gera debate sobre tecnologia educacional","summary":"O endosso da Primeira-Dama Melania Trump aos robôs humanoides da Figure AI como tutores domiciliares movidos por AI acendeu um intenso debate entre educadores, pais e psicólogos infantis. Os defensores citam o potencial de instrução perfeitamente personalizada; os críticos alertam sobre riscos ao desenvolvimento social.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/melania-trump-wants-a-robot-to-homeschool-your-child/","tags":["Educação","Figure AI","Política","Humanoide"],"timestamp":"2026-03-25T18:55:41Z"},{"id":"0331-010","title":"Drones lava-janelas da Lucid Bots: 20 milhões para escalar produção com demanda acima da oferta","summary":"A Lucid Bots está construindo uma segunda unidade de fabricação para atender à crescente demanda por seus drones autônomos de lavagem de janelas e lavagem a jato. Com os proprietários de edifícios cada vez mais relutantes em enviar trabalhadores em andaimes, a limpeza externa robótica passou de novidade a necessidade.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/lucid-bots-raises-20m-to-keep-up-with-demand-for-its-window-washing-drones/","tags":["Drones","Limpeza","Imóveis Comerciais","Escala"],"timestamp":"2026-03-25T11:00:00Z"},{"id":"0331-011","title":"Pulseira EMG controla mão protética com precisão por dedo individual","summary":"Uma pulseira EMG desenvolvida no MIT lê simultaneamente 34 sinais musculares do antebraço para fornecer controle individual em tempo real dos dedos de uma mão protética. O sistema não invasivo alcança resultados antes só possíveis com eletrodos implantados, exigindo menos de 20 horas de treinamento do usuário.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["Próteses","EMG","Wearable","Acessibilidade"],"timestamp":"2026-03-25T06:00:09Z"},{"id":"0331-012","title":"Mão robótica sem motor usa liga de memória de forma para atuação em menos de 100 ms a 180 g","summary":"Substituindo servomotores por atuadores de fio de liga com memória de forma, pesquisadores construíram uma mão robótica de cinco dedos pesando apenas 180 gramas que pode abrir e fechar dedos individuais em menos de 100 milissegundos, suficiente para tarefas de manipulação destreza.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["Mão Robótica","SMA","Leve","Atuador"],"timestamp":"2026-03-25T10:00:04Z"},{"id":"0331-013","title":"Agile Robots + Google DeepMind: a mais recente parceria AI-hardware em robótica","summary":"À medida que a corrida para dominar o mercado de AI física se intensifica, a Agile Robots se juntou à crescente lista de empresas de hardware que fazem parceria com o Google DeepMind. O acordo segue acordos similares entre DeepMind e Boston Dynamics, Figure AI e Apptronik.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/agile-robots-becomes-the-latest-robotics-company-to-partner-with-google-deepmind/","tags":["Agile Robots","DeepMind","AI","Parceria"],"timestamp":"2026-03-24T12:05:00Z"},{"id":"0331-014","title":"Lições da guerra de drones na Ucrânia: como a AI de combate autônomo está remodelando a segurança de veículos autônomos","summary":"Técnicas de navegação sem GPS, defesa contra falsificação de sensores e robustez de AI adversarial desenvolvidas para drones de combate ucranianos estão sendo adaptadas para veículos autônomos civis. A transferência de tecnologia entre domínios representa um caso único de inovação militar precedendo aplicações de consumo.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-drone-warfare","tags":["Militar","Veículos Autônomos","Segurança","Transferência de Tecnologia"],"timestamp":"2026-03-24T13:00:05Z"},{"id":"0331-015","title":"O colapso do restaurante Haidilao AgiBot: um conto de advertência sobre implantação robótica","summary":"O vídeo viral de um garçom humanoide AgiBot dançando descontroladamente em um restaurante do Vale do Silício se tornou um estudo de caso sobre implantação robótica excessivamente confiante. O incidente revela como casos extremos em ambientes reais expõem lacunas em sistemas robóticos treinados em simulação.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/restaurant-dancing-robot-went-wild-hot-pot-cupertino-haidilao-agibot/","tags":["AgiBot","Implantação","Falha","Restaurante"],"timestamp":"2026-03-19T21:13:50Z"},{"id":"0331-016","title":"Transferência de habilidades entre morfologias permite que braços robóticos aprendam com demonstrações humanoides","summary":"Um novo framework de aprendizado baseado em intenção permite que um braço robótico de mesa aprenda habilidades demonstradas por um robô humanoide completo, apesar de estruturas corporais radicalmente diferentes. A percepção chave é que as intenções de tarefa podem ser abstraídas da forma física e redirecionadas para novos corpos.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-bodies-skills-intention-based.html","tags":["Aprendizado por Transferência","Cross-Embodiment","Habilidade","AI"],"timestamp":"2026-03-30T13:20:04Z"},{"id":"0331-017","title":"Enxame sem cérebro do Georgia Tech: inteligência coletiva mecânica demonstrada","summary":"O enxame robótico puramente mecânico do Georgia Tech — o primeiro a alcançar comportamento coletivo orientado a objetivos sem eletrônica — representa uma mudança de paradigma na robótica de enxame. Os robôs usam interações de travamento por forma física para navegar coletivamente em direção a fontes de luz.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["Enxame","Inteligência Coletiva","Georgia Tech","Mecânico"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0331-018","title":"Série A de 500 milhões da Mind Robotics: a nova startup de robôs de fábrica do CEO da Rivian","summary":"RJ Scaringe captou meio bilhão de dólares para a Mind Robotics, apostando que robôs de fábrica projetados especificamente para suas tarefas — não com forma humana — dominarão a automação industrial. A primeira plataforma da empresa é construída especificamente para operações de montagem de EV.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/rivian-mind-robotics-series-a-500m-fund-raise-industrial-ai-powered-robots/","tags":["Mind Robotics","Financiamento","EV","Industrial"],"timestamp":"2026-03-11T16:12:02Z"},{"id":"0331-019","title":"Robô de entrega Rivr da Amazon sobe escadas: da porta de entrada ao destino","summary":"O robô de entrega com rodas da Rivr combina uma base com rodas e apêndices retráteis para subir escadas, navegando em edifícios residenciais de vários andares sem elevadores. A aquisição da Rivr pela Amazon sinaliza a intenção da empresa de eventualmente oferecer entrega domiciliar autônoma para qualquer endereço.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/amazon-acquires-rivr-maker-of-a-stair-climbing-delivery-robot/","tags":["Amazon","Entrega","Última Milha","Escadas"],"timestamp":"2026-03-19T23:28:37Z"},{"id":"0331-020","title":"Colheitadeira de tomates com AI prevê dificuldade de colheita e aumenta produção em 35%","summary":"Um novo robô agrícola usa visão computacional e aprendizado de máquina para prever a dificuldade de colher cada tomate antes de se aproximar, priorizando primeiro as colheitas fáceis para maximizar a taxa total de colheita. Testes em estufa mostram 35% mais rendimento e 28% menos consumo de energia por quilograma colhido.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["AgriRobótica","Colheita","AI","Eficiência"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0331-021","title":"Qualcomm IQ10 vs Nvidia: a guerra de chips para cérebros de robôs humanoides começou","summary":"A parceria da Qualcomm com a Neura Robotics para usar seu processador AI IQ10 como plataforma de computação para um novo robô humanoide marca o primeiro desafio comercial sério à dominância da Nvidia na computação robótica. O IQ10 oferece 40 TOPS abaixo de 20 W, uma proposta convincente para humanoides movidos a bateria.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/09/qualcomms-partnership-with-neura-robotics-is-just-the-beginning/","tags":["Qualcomm","Neura Robotics","Chips","Competição"],"timestamp":"2026-03-09T15:58:11Z"}]};
